// ========================================================
// NAV + SETUP
// ========================================================
function goTo(id) {
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  window.scrollTo(0,0);
}

function selectRole(el, role) {
  document.querySelectorAll('.role-card').forEach(c=>c.classList.remove('selected'));
  el.classList.add('selected');
  S.role = role;
  showPathPreview(role);
}

function showPathPreview(role) {
  const R = ROLES[role];
  const pp = document.getElementById('path-preview');
  const steps = document.getElementById('pp-steps');
  pp.classList.add('visible');
  steps.innerHTML = R.pathSteps.map((s,i)=>`
    ${i>0?'<div class="pp-arrow">to</div>':''}
    <div class="pp-step${s.a?' accent':''}">${s.t}</div>
  `).join('');
}

