const API = { url: 'https://script.google.com/macros/s/AKfycbx_hE36G5zn8evEoIge02aR-5q5fnPQKiqtay_7v4DkgXud3DJqpbhc7J3XQ9WTh2Y/exec' };

async function testConn() {
  connStatus('spin','Testing connection...');
  try {
    const r = await fetch(API.url+'?action=ping',{cache:'no-store'});
    const d = await r.json();
    if (d.ok) connStatus('ok','Connected -- '+(d.app||'EscapeTheArchive_v4'));
    else connStatus('err','Ledger error: '+JSON.stringify(d));
  } catch(e){ connStatus('err','Connection failed: '+e.message); }
}
function connStatus(state,msg){
  // Update both the header dot (conn-dot) and the config screen dot (conn-dot-cfg)
  ['conn-dot','conn-dot-cfg'].forEach(id => {
    const el = document.getElementById(id);
    if(el) el.className='sdot '+(state==='ok'?'ok':state==='err'?'err':'spin');
  });
  const msgEl = document.getElementById('conn-msg');
  if(msgEl){
    msgEl.textContent=msg;
    msgEl.style.color=state==='ok'?'var(--vd)':state==='err'?'var(--el)':'var(--gi)';
  }
}
function proceedConfig(){
  goTo('screen-roles');
}

// ── Sheets sync system ───────────────────────────────────────────
// Every post() call is fire-and-forget: sends immediately, retries on failure.
// Student is NEVER blocked waiting for a save.

const _pendingSaves = [];    // queue of {body, retries, ts}
let   _isFlushing   = false;
let   _saveCount    = 0;
let   _failCount    = 0;

// Core fetch wrapper -- tries to POST to AppScript and returns true/false
async function _doPost(body) {
  if (!API.url) return false;
  // Ensure identity fields are always present
  if (!body.session_id   && S && S.sessionId)    body.session_id   = S.sessionId;
  if (!body.student_name && S && S.studentName)  body.student_name = S.studentName;
  if (!body.first_name   && S && S.firstName)    body.first_name   = S.firstName;
  if (!body.last_name    && S && S.lastName)      body.last_name    = S.lastName;
  if (!body.class_period && S && S.period)        body.class_period = S.period;
  try {
    const r = await fetch(API.url, {
      method: 'POST',
      body:   JSON.stringify(body)
      // No Content-Type header -- avoids CORS preflight with Apps Script
    });
    const text = await r.text();
    // Apps Script deployment errors return HTML instead of JSON
    if (text.trim().startsWith('<!') || text.trim().startsWith('<html')) {
      console.error('[Ledger] Deployment error -- got HTML back. Check AppScript is deployed as "Anyone" access.', body.action);
      return false;
    }
    _saveCount++;
    console.log('[Ledger] saved:', body.action, '| total saved:', _saveCount);
    _showSyncState('ok');
    return true;
  } catch (e) {
    console.warn('[Ledger] network error:', body.action, e.message);
    return false;
  }
}

// Flush the pending queue -- one at a time, max 3 retries each
async function _flushQueue() {
  if (_isFlushing || !_pendingSaves.length) return;
  _isFlushing = true;
  while (_pendingSaves.length > 0) {
    const item = _pendingSaves[0];
    const ok = await _doPost(item.body);
    if (ok) {
      _pendingSaves.shift();
    } else {
      item.retries = (item.retries||0) + 1;
      if (item.retries >= 3) {
        console.error('[Ledger] giving up after 3 retries:', item.body.action);
        _pendingSaves.shift();
        _failCount++;
      }
      break; // back off, retry later
    }
  }
  _isFlushing = false;
  _showSyncState(_pendingSaves.length > 0 ? 'pending' : 'ok');
  if (_pendingSaves.length > 0) setTimeout(_flushQueue, 6000);
}

function _showSyncState(state) {
  const n = _pendingSaves.length;
  // Top bar
  const bar = document.getElementById('global-sync-bar');
  if (bar) bar.style.background =
    state==='ok'      ? 'rgba(74,138,114,0.7)' :
    state==='pending' ? 'rgba(201,152,42,0.6)' :
                        'rgba(192,72,40,0.6)';
  // Floating badge
  const badge = document.getElementById('sync-float');
  if (badge) {
    if (state === 'pending') {
      badge.style.opacity='1'; badge.style.color='var(--go)';
      badge.textContent = 'SAVING ' + n + ' ITEM' + (n!==1?'S':'') + '...';
      badge.style.borderColor='rgba(201,152,42,0.4)';
    } else {
      badge.style.opacity='1'; badge.style.color='var(--vd)';
      badge.textContent = 'LEDGER SYNCED ✓';
      badge.style.borderColor='rgba(74,138,114,0.3)';
      setTimeout(() => { if(badge) badge.style.opacity='0'; }, 3000);
    }
  }
  // All sync-* elements in the page
  document.querySelectorAll('[id^="sync-"]').forEach(el => {
    if (el.id === 'sync-float' || el.id === 'global-sync-bar') return;
    el.textContent  = state==='ok' ? 'saved ✓' : n + ' saving...';
    el.className    = state==='ok' ? 'sync-ok'  : 'sync-err';
  });
}

// Public post() -- queues the save, fires immediately, student never waits
async function post(body) {
  // Always inject identity fields from session state
  if (!body.session_id   && S && S.sessionId)   body.session_id   = S.sessionId;
  if (!body.student_name && S && S.studentName) body.student_name = S.studentName;
  if (!body.first_name   && S && S.firstName)   body.first_name   = S.firstName;
  if (!body.last_name    && S && S.lastName)     body.last_name    = S.lastName;
  if (!body.class_period && S && S.period)       body.class_period = S.period;

  _showSyncState('pending');

  // Add to queue
  _pendingSaves.push({body, retries:0, ts:Date.now()});

  // Try immediately (non-blocking)
  _doPost(body).then(ok => {
    if (ok) {
      // Remove from queue if it succeeded immediately
      const idx = _pendingSaves.findIndex(i => i.body === body);
      if (idx >= 0) _pendingSaves.splice(idx, 1);
      _showSyncState(_pendingSaves.length ? 'pending' : 'ok');
    } else {
      // Leave in queue for retry
      setTimeout(_flushQueue, 4000);
    }
  });

  return {ok:true}; // always return ok so student flow is never blocked
}

// Legacy alias
function _updateSyncBadge() { _showSyncState(_pendingSaves.length ? 'pending' : 'ok'); }

// ── V3 API helpers// ── V3 API helpers ────────────────────────────────────────────────────────

async function recordSmoothness(room, rating, whatChanged, madeTrust, reflection) {
  S2.smoothnessRatings.push(rating);
  S2.coherenceSum += rating;
  S2.coherenceCount++;
  const avg = S2.coherenceSum / S2.coherenceCount;
  await post({action:'recordSmoothnessCheck', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, room, coherence_rating:rating, what_changed:whatChanged||'',
    made_you_trust:madeTrust||'', reflection:reflection||''});
  await post({action:'updateSession', session_id:S.sessionId, coherence_avg:Math.round(avg*10)/10});
  if(rating >= 4) {
    showToast('Smoothness Warning',
      'You rated your understanding at '+rating+'/5. That is high for a contested archive. What in the record produced that feeling? What in you wanted to feel certain? What would have to be missing for this to feel so settled?', 6000);
  }
}

async function recordSaturationCheck(room) {
  S2.saturationCount++;
  const THRESHOLD = 12;
  if(S2.saturationCount >= THRESHOLD && !S2.saturationFired) {
    S2.saturationFired = true;
    showModal('Managed Abundance', 'You Have Now Seen ' + S2.saturationCount + ' Sources',
      'You have now encountered many sources. Are you more certain or less certain than when you started? Name what changed -- or what did not change despite everything you have read. Then name what the volume made it harder to ask. Did fatigue change your willingness to question? More sources is not more evidence. Saturation is not completeness.',
      'AS-5 Synthesis Interrogation: what would need to be excluded to produce this level of coherence?'
    );
    const resp = await promptUser('Saturation Note',
      'Name what this abundance made harder to ask. Did you find yourself wanting it to be enough? Did you mistake volume for completeness at any point? Name the moment, if there was one, when you started to feel that you had seen enough -- and ask whether that feeling was earned.');
    if(resp) {
      const recognized = resp.toLowerCase().includes('less') ||
        resp.toLowerCase().includes('uncertain') ||
        resp.toLowerCase().includes('obscur') ||
        resp.toLowerCase().includes('not more');
      await post({action:'recordSaturationEvent', session_id:S.sessionId, student_name:S.studentName,
        class_period:S.period, room, sources_seen_count:S2.saturationCount, student_response:resp,
        recognized_abundance:recognized});
      if(recognized) {
        gainPts(30, 'Recognized managed abundance -- saturation is not completeness (+30)', 'saturation');
        earnTrajectoryAction('saturation_recognized');
        showToast('Saturation Recognized','You have named what abundance obscured. That is the harder historical skill -- not finding more, but recognizing when more stops clarifying.');
      }
      await post({action:'updateSession', session_id:S.sessionId, saturation_recognized:recognized});
    }
  }
}

async function promptUser(title, prompt) {
  return new Promise(resolve => {
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(10,12,8,0.9);z-index:1400;display:flex;align-items:center;justify-content:center;';
    overlay.innerHTML = `<div style="background:var(--gv);border:0.5px solid rgba(201,152,42,0.28);padding:2rem;max-width:520px;width:90%;">
      <div style="font-family:JetBrains Mono,monospace;font-size:8px;letter-spacing:0.18em;color:var(--gi);text-transform:uppercase;margin-bottom:0.65rem;">${title}</div>
      <div style="font-family:Crimson Pro,serif;font-size:0.86rem;color:var(--pd);font-style:italic;margin-bottom:0.85rem;">${prompt}</div>
      <textarea id="prompt-input" class="arch-textarea" style="min-height:70px;" placeholder="Your response..."></textarea>
      <div style="margin-top:0.7rem;display:flex;gap:0.6rem;">
        <button class="btn-gold" style="font-size:0.76rem;padding:0.5rem 1rem;" onclick="this.closest('div').parentElement.parentElement.__resolve(document.getElementById('prompt-input').value);this.closest('div').parentElement.parentElement.remove();">Record and continue</button>
        <button class="btn-ghost" style="font-size:0.76rem;" onclick="this.closest('div').parentElement.parentElement.__resolve('');this.closest('div').parentElement.parentElement.remove();">Skip</button>
      </div>
    </div>`;
    overlay.__resolve = resolve;
    document.body.appendChild(overlay);
    setTimeout(() => document.getElementById('prompt-input')?.focus(), 100);
  });
}

async function recordProtocol(artifactId, artifactName, decision, accessCondition, reason) {
  S2.protocolDecisions.push({artifactId, decision, reason});
  gainPts(20, 'Protocol decision: '+decision+' for '+artifactName, 'protocol');
  showToast('Protocol Decision Recorded', 'Access condition recorded for '+artifactName+'. This decision is part of your archival record -- it shows how you thought about access, not just what you found.');
  if(decision === 'defer') earnTrajectoryAction('protocol_defer');
  if(decision === 'open_restricted') earnTrajectoryAction('community_named');
  await post({action:'recordProtocolDecision', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, room:currentRoom(), artifact_id:artifactId, artifact_name:artifactName,
    decision, access_condition:accessCondition||'', reason:reason||''});
  await post({action:'updateSession', session_id:S.sessionId,
    protocol_decisions_ct:S2.protocolDecisions.length});
}

async function recordRefusal(artifactId, artifactName, decision, communityNamed, reason) {
  S2.refusalDecisions.push({artifactId, decision, reason});
  gainPts(30, 'Refusal/return decision: '+decision, 'ethics');
  earnTrajectoryAction('refusal_made');
  if(communityNamed) earnTrajectoryAction('community_named');
  showToast('Decision Recorded','Your decision to '+decision.replace(/_/g,' ')+' this artifact is part of your historical record. It will appear in your final output and in the teacher record. This is historical judgment, not a bonus action.');
  await post({action:'recordRefusal', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, room:currentRoom(), artifact_id:artifactId, artifact_name:artifactName,
    decision, community_named:communityNamed||'', reason:reason||''});
  await post({action:'updateSession', session_id:S.sessionId,
    refusals_ct:S2.refusalDecisions.length});
}

async function markUnarchivable(markerText, markerType) {
  S2.unarchivableMarkers.push({text:markerText, type:markerType});
  gainPts(25, 'Named unarchivable: '+markerType, 'ethics');
  earnTrajectoryAction('unarchivable_marked');
  showToast('Remnant Recorded','Added to What Cannot Be Reconstructed. This is part of your historical record. A responsible claim names what the archive cannot account for -- this is not supplementary to your claim, it is part of it.');
  renderRemnantPanel();
  await post({action:'markUnarchivable', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, room:currentRoom(), marker_text:markerText, marker_type:markerType||''});
  await post({action:'updateSession', session_id:S.sessionId,
    unarchivable_ct:S2.unarchivableMarkers.length});
}

async function recordLimitation(taskId, claimText, limitNamed, limitType) {
  S2.limitationClaims.push({taskId, claimText, limitNamed});
  gainPts(20, 'Limitation claim named: '+limitType, 'limitation');
  earnTrajectoryAction('limitation_made');
  await post({action:'recordLimitationClaim', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, room:currentRoom(), task_id:taskId, claim_text:claimText||'', limit_named:limitNamed||'',
    limit_type:limitType||''});
  await post({action:'updateSession', session_id:S.sessionId,
    limitation_claims_ct:S2.limitationClaims.length});
}

async function recordRoleShift(oldRoleSelf, newRoleSelf, reflection) {
  S2.roleShifts.push({from:oldRoleSelf, to:newRoleSelf});
  gainPts(15, 'Named role shift: '+oldRoleSelf+' to '+newRoleSelf, 'metacognition');
  await post({action:'recordRoleShift', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, room:currentRoom(), old_role_self:oldRoleSelf, new_role_self:newRoleSelf,
    reflection:reflection||''});
}

async function recordHandoff(artifactId, artifactName, decision, reasoning, community) {
  S2.handoffDecision = {artifactId, decision, reasoning};
  const pts = {publish:0, return_to_community:40, hold_pending:25, mark_contested:35}[decision] || 0;
  if(decision === 'hold_pending') earnTrajectoryAction('handoff_hold');
  if(decision === 'mark_contested') earnTrajectoryAction('handoff_contest');
  if(decision === 'return_to_community') earnTrajectoryAction('refusal_made');
  if(pts > 0) gainPts(pts, 'Handoff decision: '+decision.replace(/_/g,' ')+' (+'+pts+')', 'ethics');
  await post({action:'recordHandoffDecision', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, artifact_id:artifactId, artifact_name:artifactName,
    decision, reasoning:reasoning||'', community_if_applicable:community||''});
}

async function recordEnding(path, reflection) {
  S2.endingPath = path;
  const ending = ENDINGS[path];
  await post({action:'recordParallelEnding', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, ending_path:path, ending_reflection:reflection||'', pts_at_end:S2.pts});
  await post({action:'updateSession', session_id:S.sessionId, ending_path:path});
  showModal('Ending Unlocked', ending.label,
    ending.icon + ' ' + ending.desc,
    'Your archive points: '+S2.pts+'. Your ending reflects how you entered, not just what you found.'
  );
}

// Remnant panel renderer
function renderRemnantPanel() {
  ['rem-pro','rem-r1'].forEach(id => {
    const el = document.getElementById(id);
    if(!el) return;
    if(!S2.unarchivableMarkers.length) {
      el.innerHTML = '<div class="locker-empty">Nothing marked yet.</div>';
      return;
    }
    el.innerHTML = S2.unarchivableMarkers.map(m =>
      `<div style="background:rgba(139,58,42,0.07);border-left:2px solid var(--er);padding:0.28rem 0.45rem;font-family:Crimson Pro,serif;font-size:0.68rem;color:var(--pd);font-style:italic;margin-bottom:2.5px;">${m.text}</div>`
    ).join('');
  });
}

// Smoothness check prompt (before room advance)
async function showSmoothnessCheck(room) {
  const rating = await new Promise(resolve => {
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(10,12,8,0.88);z-index:1400;display:flex;align-items:center;justify-content:center;';
    overlay.innerHTML = `<div style="background:var(--gv);border:0.5px solid rgba(201,152,42,0.26);padding:1.8rem;max-width:500px;width:90%;">
      <div style="font-family:JetBrains Mono,monospace;font-size:8px;letter-spacing:0.18em;color:var(--gi);text-transform:uppercase;margin-bottom:0.6rem;">Before you advance -- Smoothness Check</div>
      <div style="font-family:Crimson Pro,serif;font-size:0.86rem;color:var(--pd);font-style:italic;margin-bottom:1rem;">Rate how coherent your understanding of this archive feels right now (1 = very uncertain, 5 = very settled). If you are above 4, pause before advancing. Ask: what in this archive produced that feeling? What in you wanted to feel settled? What felt like relief -- and was that relief earned by evidence or produced by the design of what you were shown? High coherence in a contested archive is a warning sign, not an achievement.</div>
      <div style="display:flex;gap:0.5rem;margin-bottom:0.85rem;flex-wrap:wrap;">
        ${[1,2,3,4,5].map(n=>`<button class="btn-ghost" style="flex:1;text-align:center;" onclick="this.closest('div').parentElement.parentElement.__resolve(${n});this.closest('div').parentElement.parentElement.remove();">${n}</button>`).join('')}
      </div>
      <div style="font-family:JetBrains Mono,monospace;font-size:7px;color:var(--sm);letter-spacing:0.08em;">1=very uncertain &nbsp;&nbsp; 5=fully settled</div>
    </div>`;
    overlay.__resolve = resolve;
    document.body.appendChild(overlay);
  });
  const madeTrust = await promptUser('What produced that feeling?',
    'What in the archive made you feel that way? Name the specific feature -- a format, an order, a silence, a volume, a label. Then ask: was that feeling earned by evidence, or produced by design? What did you want to believe?');
  await recordSmoothness(room, rating, '', madeTrust, '');
}

// Handoff decision UI (called before final submission)
async function showHandoffDecision() {
  return new Promise(resolve => {
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(10,12,8,0.92);z-index:1400;display:flex;align-items:center;justify-content:center;';
    overlay.innerHTML = `<div style="background:var(--gv);border:0.5px solid rgba(201,152,42,0.28);padding:2rem;max-width:540px;width:92%;">
      <div style="font-family:JetBrains Mono,monospace;font-size:8px;letter-spacing:0.2em;color:var(--go);text-transform:uppercase;margin-bottom:0.7rem;">Handoff Decision -- What Happens to This Claim</div>
      <div style="font-family:IM Fell English SC,serif;font-size:1.15rem;color:var(--iv);margin-bottom:0.6rem;">What will you do with what you have found?</div>
      <div style="font-family:Crimson Pro,serif;font-size:0.84rem;color:var(--pd);font-style:italic;margin-bottom:1rem;">Publication is not the default good. Returning, holding, and marking as contested are equally legitimate historical decisions. This choice appears in your final record and in the teacher view. It is part of your historical argument.</div>
      <div style="display:flex;flex-direction:column;gap:0.45rem;">
        <button class="btn-task" onclick="handleHandoff('publish','Publish -- I can support this claim with named limits',this)">Publish -- I can support this claim, and I have named what it cannot say</button>
        <button class="btn-task" onclick="handleHandoff('return_to_community','Return -- this material belongs to its source community',this)">Return to the source community -- this record is not mine to exhibit without their involvement</button>
        <button class="btn-task" onclick="handleHandoff('hold_pending','Hold -- the evidence is not yet sufficient',this)">Hold pending further work -- publishing now would overstate what the evidence supports</button>
        <button class="btn-task" onclick="handleHandoff('mark_contested','Contest -- this claim is in legitimate dispute',this)">Mark as contested -- publish with an explicit dispute marker naming what is unresolved</button>
      </div>
      <div id="handoff-reason-block" style="display:none;margin-top:0.85rem;">
        <div style="font-family:Crimson Pro,serif;font-size:0.82rem;color:var(--pd);font-style:italic;margin-bottom:0.4rem;">Explain your reasoning. This is not a summary of your work -- it is a statement of why you made this decision and what it means for the historical record.</div>
        <textarea class="arch-textarea" id="handoff-reason" style="min-height:65px;" placeholder="Why this decision, and what does it mean for the exhibit?"></textarea>
        <button class="btn-gold" style="font-size:0.76rem;padding:0.5rem 1.1rem;margin-top:0.5rem;" onclick="confirmHandoff()">Record this decision</button>
      </div>
    </div>`;
    overlay.__resolve = resolve;
    overlay.id = 'handoff-overlay';
    document.body.appendChild(overlay);
  });
}

let _handoffChoice = null;
function handleHandoff(choice, label, btn) {
  _handoffChoice = {choice, label};
  document.querySelectorAll('#handoff-overlay .btn-task').forEach(b=>b.style.borderColor='');
  btn.style.borderColor = 'rgba(201,152,42,0.6)';
  document.getElementById('handoff-reason-block').style.display = 'block';
}

async function confirmHandoff() {
  const reason = document.getElementById('handoff-reason')?.value?.trim();
  if(!reason || reason.length < 10) {
    showToast('Reasoning required','Explain your decision in at least one sentence. This is part of your archival record.');
    return;
  }
  const overlay = document.getElementById('handoff-overlay');
  if(overlay && overlay.__resolve) overlay.__resolve({choice:_handoffChoice.choice, reason});
  if(overlay) overlay.remove();
  gainPts(15, 'Handoff decision recorded (+15)', 'ethics');
  await recordHandoff('final_claim','Final Exhibit Claim', _handoffChoice.choice, reason, '');
  await post({action:'updateSession', session_id:S.sessionId,
    status:'handoff_complete', archive_pts:S2.pts});
  setSyncEl('sync-final', true);
}

// Parallel ending chooser -- fires when the student has earned any trajectory action,
// or when they have completed both room locks (institutional path always available).
// NOT gated behind 900 pts. Paths form through choices, not points.
async function showEndingChooser() {
  const hasTrajActions = computeTrajectories().length > 0;
  const hasLocksOpen = S3.trajectoryActions.has('both_locks_open');
  if(!hasTrajActions && !hasLocksOpen) return;
  // Build available endings: those the student has trajectory actions toward
  // plus Institutional Auditor if both room locks have been completed
  const available = Object.keys(ENDINGS).filter(id =>
    canUnlockEnding(id) || (id === 'head_curator' && S3.trajectoryActions.has('both_locks_open'))
  );
  if(available.length === 0) {
    // Offer all five but note which are earned vs aspirational
    available.push(...Object.keys(ENDINGS));
  }
  return new Promise(resolve => {
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(10,12,8,0.94);z-index:1500;display:flex;align-items:center;justify-content:center;overflow-y:auto;padding:2rem 0;';
    const trajectories = computeTrajectories();
    const earnedIds = new Set(trajectories.map(t => t.id));
    const cards = Object.entries(ENDINGS).map(([id,e])=> {
      const isEarned = earnedIds.has(id);
      const borderStyle = isEarned ? 'border-color:rgba(201,152,42,0.55);background:rgba(201,152,42,0.04);' : '';
      const earnedBadge = isEarned ? '<span style="font-family:JetBrains Mono,monospace;font-size:6.5px;letter-spacing:0.12em;color:var(--go);text-transform:uppercase;margin-left:0.5rem;">your path</span>' : '';
      return `<button class="btn-task" style="margin-bottom:0.5rem;padding:0.75rem 1rem;text-align:left;${borderStyle}" onclick="chooseEnding('${id}',this)">
        <div style="font-family:'IM Fell English SC',serif;font-size:0.9rem;color:var(--iv);margin-bottom:0.25rem;">${e.icon} ${e.label}${earnedBadge}</div>
        <div style="font-family:'Crimson Pro',serif;font-size:0.75rem;color:var(--pd);font-style:italic;">${e.desc}</div>
        <div style="font-family:'Crimson Pro',serif;font-size:0.7rem;color:var(--sm);margin-top:0.2rem;">${e.trajectory_desc}</div>
      </button>`;
    }).join('');
    overlay.innerHTML = `<div style="background:var(--gv);border:0.5px solid rgba(201,152,42,0.28);padding:2rem;max-width:560px;width:92%;">
      <div style="font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.2em;color:var(--go);text-transform:uppercase;margin-bottom:0.7rem;">Paths Have Opened -- Choose Your Relation to This Archive</div>
      <div style="font-family:'IM Fell English SC',serif;font-size:1.1rem;color:var(--iv);margin-bottom:0.6rem;">How will you leave?</div>
      <div style="font-family:'Crimson Pro',serif;font-size:0.84rem;color:var(--pd);font-style:italic;margin-bottom:0.6rem;">Paths shown in gold are ones your choices have already moved toward. All five remain open.</div>
      <div style="font-family:'Crimson Pro',serif;font-size:0.78rem;color:var(--sm);margin-bottom:1rem;">Paths shown in gold are the ones your choices have already moved toward. All five remain open. None of them is the apex. Each represents a different relation to the archive -- not different amounts of skill.</div>
      ${cards}
      <div id="ending-reflection-block" style="display:none;margin-top:0.85rem;">
        <textarea class="arch-textarea" id="ending-reflection" style="min-height:65px;" placeholder="How did your relation to this archive change? Not your role title -- your actual position. What were you doing at the start? What are you doing now? What does this ending mean for how you enter the next archive?"></textarea>
        <button class="btn-gold" style="font-size:0.76rem;padding:0.5rem 1.1rem;margin-top:0.5rem;" onclick="confirmEnding()">Confirm your ending</button>
      </div>
    </div>`;
    overlay.__resolve = resolve;
    overlay.id = 'ending-overlay';
    document.body.appendChild(overlay);
  });
}

let _endingChoice = null;
function chooseEnding(path, btn) {
  _endingChoice = path;
  document.querySelectorAll('#ending-overlay .btn-task').forEach(b=>b.style.borderColor='');
  btn.style.borderColor = 'rgba(201,152,42,0.6)';
  document.getElementById('ending-reflection-block').style.display = 'block';
}

async function confirmEnding() {
  const reflection = document.getElementById('ending-reflection')?.value?.trim();
  if(!reflection || reflection.length < 15) {
    showToast('Reflection required','Write at least one sentence about this ending before confirming.');
    return;
  }
  const overlay = document.getElementById('ending-overlay');
  if(overlay && overlay.__resolve) overlay.__resolve({path:_endingChoice, reflection});
  if(overlay) overlay.remove();
  gainPts(20, 'Ending chosen: '+_endingChoice+' (+20)', 'synthesis');
  await recordEnding(_endingChoice, reflection);
  await post({action:'updateSession', session_id:S.sessionId,
    ending_path:_endingChoice, status:'ending_chosen', archive_pts:S2.pts});
  setSyncEl('sync-final', true);
}

function setSyncEl(id,ok){
  const el=document.getElementById(id);
  if(el){el.textContent=ok?'synced':'offline';el.className=ok?'sync-ok':'sync-err';}
}

// ========================================================
// GAME START
// ========================================================
// Helper: wrap any promise with a timeout, resolving to null on timeout
function _withTimeout(promise, ms) {
  return Promise.race([
    promise,
    new Promise(resolve => setTimeout(() => resolve(null), ms))
  ]);
}

async function startGame(){
  const firstName = (document.getElementById('sfirst')?.value||'').trim();
  const lastName  = (document.getElementById('slast')?.value||'').trim();
  const period    = document.getElementById('speriod')?.value||'';
  const errEl     = document.getElementById('reg-error');

  // Client-side validation
  if(!firstName){ if(errEl){errEl.textContent='First name is required.';errEl.style.display='block';} return; }
  if(!lastName){  if(errEl){errEl.textContent='Last name is required.';errEl.style.display='block';} return; }
  if(!period){    if(errEl){errEl.textContent='Please select your class period.';errEl.style.display='block';} return; }
  if(errEl) errEl.style.display='none';

  // Show "starting" briefly on the button
  const btn = document.querySelector('#screen-config .btn-gold');
  if(btn){ btn.disabled=true; btn.textContent='Starting...'; }

  try {
    // ── Set up session state IMMEDIATELY -- zero network dependency ──
    S.studentName = firstName + ' ' + lastName;
    S.firstName   = firstName;
    S.lastName    = lastName;
    S.period      = period;
    if(!S.role) S.role='lead';
    S.sessionId = 'SES_'+Date.now()+'_'+Math.random().toString(36).slice(2,6);

    // Build game UI -- all local, instant
    applyRoleUI();
    renderLocker();
    buildPrologueTasks();
    buildRoom1();

    // ── Navigate NOW -- never wait for network ──
    if(btn){ btn.disabled=false; btn.textContent='Enter the Archive'; }
    if(errEl) errEl.style.display='none';
    goTo('screen-prologue');
    startTimer();
    setTimeout(() => { updateRoomProgress('prologue'); updateRoomProgress('room1'); }, 250);

    // ── Fire all network calls in the background ──
    // validateStudent: advisory only, 4s timeout, never blocks navigation
    _withTimeout(post({action:'validateStudent', first_name:firstName,
      last_name:lastName, class_period:period}), 4000)
      .then(vRes => {
        if(vRes && !vRes.ok && !vRes.network_error)
          console.warn('[Ledger] validateStudent advisory:', vRes.error);
      }).catch(()=>{});

    // startSession: fire and forget
    _withTimeout(post({action:'startSession', session_id:S.sessionId,
      student_name:S.studentName, first_name:firstName, last_name:lastName,
      role:S.role, class_period:S.period, team_name:''}), 6000)
      .then(res => { setSyncEl('sync-pro', res&&res.ok); })
      .catch(()=>{});

  } catch(err) {
    console.error('startGame error:', err);
    if(btn){ btn.disabled=false; btn.textContent='Enter the Archive'; }
    if(errEl){
      errEl.textContent='Error starting session: '+err.message+'. Please refresh.';
      errEl.style.display='block'; errEl.style.color='var(--el)';
    }
  }
}


// ── Load registration data from AppScript on page load ──────────
async function loadRegistration() {
  const sel = document.getElementById('speriod');
  const STATIC_PERIODS = ['1','2','3','4','5','6','7'];

  async function setStaticPeriods() {
    if(sel) {
      sel.innerHTML = '<option value="">Select your period...</option>' +
        STATIC_PERIODS.map(p=>`<option value="${p}">Period ${p}</option>`).join('');
    }
  }

  // Show static periods IMMEDIATELY -- dropdown always works, even offline
  setStaticPeriods();

  // Try to upgrade with teacher-configured periods in background (3s timeout)
  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 3000);
    const r = await fetch(API.url + '?action=getRegistration', {
      cache:'no-store',
      signal: controller.signal
    });
    clearTimeout(timeout);
    const d = await r.json();
    if(d && d.ok && d.periods && d.periods.length) {
      if(sel) {
        sel.innerHTML = '<option value="">Select your period...</option>' +
          d.periods.map(p => `<option value="${p.value}">${p.label}</option>`).join('');
      }
      if(d.scoring) window._teacherScoring = d.scoring;
    }
  } catch(e) {
    console.warn('loadRegistration: using static periods,', e.message);
  }
}

// Helper: attach class_period to every post that needs it
function postWithPeriod(body) {
  return post({...body, class_period: S.period || ''});
}

function applyRoleUI(){
  const R=ROLES[S.role];
  // badges
  ['pro','r1'].forEach(sc=>{
    const b=document.getElementById('hdr-badge-'+sc);
    if(b){b.textContent=R.label;b.className='hdr-role-badge '+R.color;}
  });
  // path indicators
  const pip=document.getElementById('pi-pro');
  if(pip) pip.textContent=R.piFocus.pro;
  const pir=document.getElementById('pi-r1');
  if(pir) pir.textContent=R.piFocus.r1;
  // role frames prologue
  ['lead','evidence','analyst','signal'].forEach(r=>{
    const f=document.getElementById('rf-pro-'+r);
    if(f) f.classList.toggle('visible',r===S.role);
  });
  // display name
  ['dn-pro'].forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.textContent=S.studentName;
  });
  ['dr-pro'].forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.textContent=R.label;
  });
}

