let timerInt;
// ── Live progress update on any input change ────────────────────────
document.addEventListener('input', function(e) {
  const id = e.target?.id || '';
  // Prologue annotation fields
  if(id === 'ann-claim' || id === 'ann-sources') updateRoomProgress('prologue');
  // Room 1 reflection
  if(id === 'ref-1' || id === 'ref-2') updateRoomProgress('room1');
  // Room 2 tasks
  if(id.startsWith('r2-') || id === 'r2-rank-reason' || id === 'r2-saturation-resp')
    updateRoomProgress('room2');
  // Room 3
  if(id === 'r3-echo-finding') updateRoomProgress('room3');
  // Room 4
  if(id === 'r4-platform-audit' || id === 'r4-bury-reason') updateRoomProgress('room4');
  // Room 5
  if(id === 'r5-synthesis-audit') updateRoomProgress('room5');
});

document.addEventListener('change', function(e) {
  const name = e.target?.name || '';
  const id   = e.target?.id   || '';
  if(name === 'r2conf' || id.startsWith('r2-rank')) updateRoomProgress('room2');
  if(name === 'r3mc') updateRoomProgress('room3');
  if(name === 'r4rank' || id.startsWith('r4-bury')) updateRoomProgress('room4');
});

let _timerPaused = false;
function startTimer(){
  timerInt=setInterval(()=>{
    if(_timerPaused) return;
    S.timer=Math.max(0,S.timer-1);
    const m=Math.floor(S.timer/60), s=S.timer%60;
    const str=m+':'+(s<10?'0':'')+s;
    document.querySelectorAll('[id^="tmr-"]').forEach(el=>{
      el.textContent=str;
      el.classList.toggle('low',S.timer<300);
    });
  },1000);
}
function toggleTimer(){
  _timerPaused=!_timerPaused;
  document.querySelectorAll('[id^="timer-pause-"]').forEach(btn=>{
    btn.textContent=_timerPaused?'▶':'⏸';
    btn.title=_timerPaused?'Resume timer':'Pause timer';
    btn.style.color=_timerPaused?'var(--go)':'';
  });
  if(_timerPaused) showToast('Timer Paused','Click ▶ to resume.',2000);
}

// ========================================================
// SIGNAL
// ========================================================
function setSignal(n){
  S.signal=Math.min(5,Math.max(0,n));
  document.querySelectorAll('[id^="sb-"]').forEach(c=>{
    c.querySelectorAll('.sbar').forEach((b,i)=>b.classList.toggle('lit',i<S.signal));
  });
  if(S.sessionId) post({action:'updateSession',session_id:S.sessionId,signal_score:S.signal});
}

// ========================================================
// LOCKER
// ========================================================
const ART_NAMES = {
  '001':'Intake Document 7-A',
  '002':'Executive Order 9066 Summary',
  'testimony':'Yamamoto Family Testimony, 1943',
  'wra-photo':'Photograph WRA-0043 (Official Caption)'
};

async function saveArt(id,name,room,type,provenance){
  const MAX_LOCKER = 8;
  if(S.locker.includes(id)){showToast('Already Saved',name+' is already in your locker.');return;}
  if(S.locker.length >= MAX_LOCKER){
    showToast('Locker Full','You have reached the maximum of '+MAX_LOCKER+' artifacts. Remove one before saving another.');
    return;
  }
  S.locker.push(id);
  const btn=document.getElementById('sbtn-'+id);
  if(btn){btn.textContent='Saved ✓';btn.classList.add('saved');}
  renderLocker();
  // Capacity warning at 6
  if(S.locker.length >= MAX_LOCKER - 2) {
    showToast('Locker Notice', S.locker.length+' of '+MAX_LOCKER+' slots used. Choose carefully.');
  } else {
    showToast('Evidence Locker', name+' added. You can annotate it in the locker.');
  }
  setSignal(S.signal+1);
  const res=await post({action:'saveLocker',session_id:S.sessionId,artifact_id:id,artifact_name:name,room,artifact_type:type,provenance});
  setSyncEl('sync-r1',res&&res.ok);
  if(id==='001') markTask('pt4');
  if(id==='002') markTask('r1t1');
  if(id==='testimony') { markTask('r1t4'); post({action:'saveSignal',session_id:S.sessionId,room,event:'witness_unlocked',signal_before:S.signal-1,signal_after:S.signal,delta:1}); }
}

function removeFromLocker(id){
  const idx = S.locker.indexOf(id);
  if(idx === -1) return;
  S.locker.splice(idx, 1);
  // Reset save button
  const btn = document.getElementById('sbtn-'+id);
  if(btn){ btn.textContent='Save'; btn.classList.remove('saved'); }
  renderLocker();
  showToast('Removed', (ART_NAMES[id]||id)+' removed from locker.');
}

function saveVoiceNote(cat, val){
  if(!S.voiceNotes) S.voiceNotes = {};
  S.voiceNotes[cat] = val;
}
function updateVoiceTally(){
  const count = S.voices.length;
  document.querySelectorAll('[id^="tally-voices"]').forEach(el=>{
    el.textContent=count;
    el.classList.toggle('has-items',count>0);
  });
}

function renderLocker(){
  const MAX_LOCKER = 8;
  ['lkr-pro','lkr-r1','lkr-r2','lkr-r3','lkr-r4','lkr-r5'].forEach(lid=>{
    const box=document.getElementById(lid);
    if(!box) return;
    box.innerHTML='';
    const count = S.locker.length;
    // Count badge
    const badge = document.createElement('span');
    badge.className = 'locker-count-badge';
    badge.textContent = `${count} / ${MAX_LOCKER} items saved`;
    box.appendChild(badge);
    if(!count){
      const empty = document.createElement('div');
      empty.className = 'locker-empty';
      empty.textContent = 'No artifacts saved.';
      box.appendChild(empty);
      return;
    }
    S.locker.forEach(aid=>{
      const wrap = document.createElement('div');
      wrap.style.cssText = 'margin-bottom:4px;';
      // Chip row
      const ch=document.createElement('div');
      ch.className='locker-chip';
      const dot = document.createElement('div');
      dot.className = 'ldot';
      const name = document.createElement('span');
      name.textContent = ART_NAMES[aid]||aid;
      const undo = document.createElement('span');
      undo.className = 'locker-chip-undo';
      undo.textContent = '✕ remove';
      undo.title = 'Remove from locker';
      undo.onclick = ()=>{ removeFromLocker(aid); };
      ch.appendChild(dot); ch.appendChild(name); ch.appendChild(undo);
      // Editable note
      const noteId = 'lnote-'+aid;
      const note = document.createElement('textarea');
      note.className = 'locker-note-area';
      note.id = noteId;
      note.placeholder = 'Add a note about this artifact... (optional)';
      note.value = S.lockerNotes?.[aid] || '';
      note.oninput = ()=>{ if(!S.lockerNotes) S.lockerNotes={}; S.lockerNotes[aid]=note.value; };
      wrap.appendChild(ch); wrap.appendChild(note);
      box.appendChild(wrap);
    });
  });
  // Update tally badge
  const tb = document.getElementById('tally-locker');
  if(tb){ tb.textContent=S.locker.length; tb.classList.toggle('has-items',S.locker.length>0); }
  // Update protocol checklist if shown
  updateProtocolChecklist();
}

