// ========================================================
// ================================================================
// PROLOGUE -- STEP-BY-STEP PUZZLE FUNCTIONS
// ================================================================

function buildPrologueTasks(){
  const desc2 = {
    lead:     'Examine the three hotspots in the document header.',
    evidence: 'Run the provenance check on the intake document.',
    analyst:  'Complete the source category map.',
    signal:   'Rate all five trust signals before reading for content.'
  };
  const el = document.getElementById('pt2-desc');
  if(el) el.textContent = desc2[S.role] || desc2.lead;
  // Set step 2 label
  const s2l = document.getElementById('step-2-label');
  if(s2l) s2l.textContent = desc2[S.role] || desc2.lead;
}

// ── Step helpers ─────────────────────────────────────────────────
function _advanceStep(from, to) {
  const fromEl = document.getElementById('pro-step'+from);
  const toEl   = document.getElementById('pro-step'+to);
  const fromInd = document.getElementById('step-'+from+'-indicator');
  const toInd   = document.getElementById('step-'+to+'-indicator');
  if(fromEl) fromEl.style.display = 'none';
  if(toEl)   { toEl.style.display = 'block'; toEl.scrollIntoView({behavior:'smooth',block:'start'}); }
  if(fromInd) { fromInd.classList.remove('active'); fromInd.classList.add('done'); fromInd.querySelector('.step-dot').textContent = '✓'; }
  if(toInd)   toInd.classList.add('active');
}

// ── STEP 1: Annotations submit → reveal Step 2 ───────────────────
async function submitAnnotations() {
  const claim   = document.getElementById('ann-claim')?.value?.trim();
  const sources = document.getElementById('ann-sources')?.value?.trim();
  const flag    = document.getElementById('ann-flag')?.value?.trim();

  // Show inline errors rather than relying on disappearing toast
  const annPanel = document.getElementById('pro-annotations');
  let errorMsg = '';
  if(!claim || claim.length < 3)   errorMsg = 'Field 1 is required: describe what this exhibit claims to be about.';
  else if(!sources || sources.length < 3) errorMsg = 'Field 2 is required: list the source types the document names.';

  if(errorMsg) {
    // Show error inline above the button
    let errEl = document.getElementById('ann-error');
    if(!errEl) {
      errEl = document.createElement('div');
      errEl.id = 'ann-error';
      errEl.style.cssText = 'font-family:"Crimson Pro",serif;font-size:0.8rem;color:var(--el);background:rgba(139,58,42,0.1);border:0.5px solid rgba(192,72,40,0.3);padding:0.4rem 0.6rem;margin-bottom:0.4rem;';
      annPanel?.insertBefore(errEl, annPanel.querySelector('button'));
    }
    errEl.textContent = errorMsg;
    errEl.style.display = 'block';
    // Also scroll to error
    errEl.scrollIntoView({behavior:'smooth', block:'nearest'});
    return;
  }

  // Clear any error
  const errEl = document.getElementById('ann-error');
  if(errEl) errEl.style.display = 'none';

  if(S.pro.examined) {
    // Already submitted -- just advance to step 2 in case it didn’t work
    _advanceStep(1, 2);
    const block = document.getElementById('pro-' + S.role + '-block');
    if(block) block.style.display = 'block';
    return;
  }
  S.pro.examined = true;
  markTask('pt1');
  setSignal(S.signal + 0.5);
  gainPts(10, 'Intake document annotated (+10)', 'action');

  // Show role-specific puzzle inside step 2
  const block = document.getElementById('pro-' + S.role + '-block');
  if(block) block.style.display = 'block';

  // Update step 2 heading to role-specific instruction
  const step2txt = document.getElementById('step2-label-text');
  const labels = {
    lead:     'Lead Auditor &mdash; Click the three highlighted elements in the document header',
    evidence: 'Evidence Keeper &mdash; Check whether the provenance fields are consistent',
    analyst:  'Archive Analyst &mdash; Classify each source category as present, absent, or excluded',
    signal:   'Signal Monitor &mdash; Rate all five trust signals before reading for content'
  };
  if(step2txt) step2txt.innerHTML = labels[S.role] || labels.lead;

  // Also update the task panel step 2 description
  const pt2desc = document.getElementById('pt2-desc');
  const pt2labels = {
    lead:     'Click the three highlighted elements in the document: date, caption word, and scope claim.',
    evidence: 'Check each provenance field: Consistent or Inconsistent?',
    analyst:  'Classify all five source categories as Present, Absent, or Structurally excluded.',
    signal:   'Rate all five trust signals as Earned or Unearned.'
  };
  if(pt2desc) pt2desc.textContent = pt2labels[S.role] || pt2labels.lead;

  _advanceStep(1, 2);

  showSubmitConfirm(document.getElementById('pro-annotations'), 'Annotations saved', 'Your notes on claim, sources, and flags have been recorded.');
  checkVocabBonus(claim + ' ' + sources, 'prologue');
  checkHistoryBonus(claim + ' ' + sources + ' ' + (flag||''), 'prologue');
  await post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
    room:'prologue', task_id:'PROL_001', task_label:'Intake document annotation',
    response_type:'annotation', response_value:[claim, sources, flag||'(none)'].join(' | '),
    is_correct:true, signal_delta:0.5, standards_addressed:'APUSH KC-7.3.I,AS-1',
    skill_category:'Analyzing Evidence'});
}

function proceedToRoom1() {
  if(!S.pro.examined) {
    showToast('Annotation required','Complete the intake document annotation first.');
    return;
  }
  if(!S.pro.roleTaskDone) {
    showToast('Role task incomplete','Complete your role task (Step 2) before advancing to Room 1.');
    return;
  }
  if(!S.pro.misalignDone) {
    showToast('One more step','Click the "Find the misalignment" button to identify the key problem in this record, then proceed.');
    return;
  }
  goTo('screen-room1');
}

// ── Lead Auditor: hotspot puzzle ──────────────────────────────────
let _hotspotsRevealed = new Set();
function revealHotspot(id) {
  const el = document.getElementById('hs-' + id);
  const rev = document.getElementById('hsr-' + id);
  if(!el || _hotspotsRevealed.has(id)) return;
  _hotspotsRevealed.add(id);
  el.classList.add('revealed');
  if(rev) rev.style.display = 'block';
  const prog = document.getElementById('hotspot-progress');
  if(prog) prog.textContent = _hotspotsRevealed.size + ' of 3 examined';

  if(_hotspotsRevealed.size >= 3) {
    document.getElementById('lead-hotspot-done').style.display = 'block';
    document.getElementById('btn-mis').style.display = 'inline-block';
    markTask('pt2');
    setSignal(S.signal + 1);
    gainPts(20, 'All three hotspots examined (+20)', 'analysis');
    S.pro.roleTaskDone = true;
    post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
      room:'prologue', task_id:'PROL_LEAD_HOTSPOT', task_label:'Document hotspot analysis',
      response_type:'multi_examine', response_value:'date|caption|scope all examined',
      is_correct:true, signal_delta:1, standards_addressed:'AS-1,AS-7',
      skill_category:'Analyzing Evidence'});
  }
}

// ── Evidence Keeper: provenance verdict puzzle ─────────────────────
const _provVerdicts = {};
const _provCorrect  = { date:'inconsistent', accession:'consistent', stamp:'inconsistent' };

async function provVerdict(btn, field, verdict) {
  if(_provVerdicts[field] !== undefined) return; // already answered
  _provVerdicts[field] = verdict;

  const correct = _provCorrect[field] === verdict;
  const resultEl = document.getElementById('pvr-' + field);
  btn.parentElement.querySelectorAll('.prov-btn').forEach(b => b.disabled = true);

  if(resultEl) {
    resultEl.textContent = correct
      ? (field === 'date'      ? 'Correct -- the date precedes events it claims to document'
       : field === 'accession' ? 'Correct -- accession after the war is consistent'
                               : 'Correct -- a stamp cannot verify future events')
      : (field === 'date'      ? 'Look again -- the document date and the event range overlap strangely'
       : field === 'accession' ? 'Look again -- when would you expect this to be accessioned?'
                               : 'Consider: can a document be "Verified" if it covers events that had not yet occurred?');
    resultEl.style.color = correct ? 'var(--vd)' : 'var(--er)';
    resultEl.style.display = 'block';
  }

  const allAnswered = Object.keys(_provVerdicts).length >= 3;
  if(allAnswered && !S.pro.roleTaskDone) {
    S.pro.roleTaskDone = true;
    const provResultEl = document.getElementById('prov-result');
    provResultEl.style.display = 'block';
    showSubmitConfirm(provResultEl, 'Provenance check complete', 'All three fields assessed. Inconsistencies flagged.');
    document.getElementById('btn-mis').style.display = 'inline-block';
    markTask('pt2');
    setSignal(S.signal + 1);
    gainPts(20, 'Provenance check complete (+20)', 'analysis');
    await post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
      room:'prologue', task_id:'PROL_EVID_01', task_label:'Provenance verdict',
      response_type:'multi_verdict', response_value:JSON.stringify(_provVerdicts),
      is_correct:true, signal_delta:1, standards_addressed:'AS-3,AS-8',
      skill_category:'Analyzing Evidence'});
  }
}

// ── Archive Analyst: category map puzzle ──────────────────────────
async function submitAnalystCats() {
  if(S.pro.roleTaskDone) return;
  const selects = document.querySelectorAll('#analyst-cats .cat-select');
  const vals = {};
  let allAnswered = true;
  selects.forEach(sel => {
    if(!sel.value) allAnswered = false;
    vals[sel.dataset.cat] = sel.value;
  });
  if(!allAnswered) { showToast('Classify all five', 'Every row needs a classification before submitting.'); return; }

  // Score: testimony and press should be absent/structural, gov and photo should be present
  const correct = {
    gov:       vals.gov       === 'present',
    photo:     vals.photo     === 'present',
    testimony: vals.testimony === 'absent' || vals.testimony === 'structural',
    press:     vals.press     === 'absent' || vals.press     === 'structural',
    legal:     vals.legal     === 'absent' || vals.legal     === 'structural',
  };
  const score = Object.values(correct).filter(Boolean).length;

  // Give per-row feedback by coloring selects
  selects.forEach(sel => {
    const cat = sel.dataset.cat;
    sel.style.borderColor = correct[cat]
      ? 'rgba(74,138,114,0.6)' : 'rgba(192,72,40,0.5)';
  });

  S.pro.roleTaskDone = true;
  const resultEl = document.getElementById('analyst-result');
  resultEl.style.display = 'block';
  showSubmitConfirm(resultEl, 'Category map submitted', `${score}/5 categories correctly classified.`);
  resultEl.innerHTML =
    score >= 4
      ? `<strong>${score}/5 correct.</strong> You have named what is structurally absent before reading what is present. First-person testimony and community legal records are not named as source types -- that absence is a curatorial decision, not an oversight.`
      : `<strong>${score}/5 correct.</strong> Review the highlighted rows. The key question: which source types could NOT be produced by the government itself?`;
  // Disable submit button to prevent resubmission confusion
  const submitBtn = document.querySelector('#pro-analyst-block .btn-task');
  if(submitBtn){ submitBtn.disabled = true; submitBtn.textContent = 'Category map submitted ✓'; submitBtn.style.opacity = '0.6'; }
  // Show why field
  const whyWrap = document.getElementById('analyst-why-wrap');
  if(whyWrap) whyWrap.style.display = 'block';
  document.getElementById('btn-mis').style.display = 'inline-block';
  markTask('pt2');
  setSignal(S.signal + 1);
  gainPts(score >= 4 ? 25 : 15, 'Category map submitted (+' + (score >= 4 ? 25 : 15) + ')', 'analysis');

  if(vals.testimony === 'structural' || vals.testimony === 'absent') {
    S.voices.push('First-person testimony from affected communities');
  }
  if(vals.press === 'structural' || vals.press === 'absent') {
    S.voices.push('Independent press outside government channels');
  }
  if(vals.legal === 'structural' || vals.legal === 'absent') {
    S.voices.push('Legal challenges and community petitions');
  }
  updateVoiceTally();
  // Render voices panel with categories + why-note fields
  const vc = document.getElementById('vc-pro');
  if(vc) {
    const absentCats = Object.entries(vals).filter(([k,v])=>v==='absent'||v==='structural');
    if(absentCats.length === 0) {
      vc.innerHTML = '<span style="font-size:0.72rem;">None flagged yet.</span>';
    } else {
      const catNames = {gov:'Government correspondence',photo:'Government photography',testimony:'First-person testimony',press:'Independent press',legal:'Legal challenges & petitions'};
      const items = absentCats.map(([k,v])=>`
        <div class="voices-cat-item" data-cat="${k}">
          <strong>${catNames[k]||k}</strong> — <em style="font-size:0.68rem;opacity:0.75;">${v==='structural'?'Structurally excluded':'Absent'}</em>
          <textarea class="voices-why-input" placeholder="Why is this absent? (optional)" oninput="saveVoiceNote('${k}',this.value)"></textarea>
        </div>`).join('');
      vc.innerHTML = `<div class="voices-cat-list">${items}</div>`;
    }
  }
  await post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
    room:'prologue', task_id:'PROL_ANAL_01', task_label:'Source category map',
    response_type:'classification', response_value:JSON.stringify(vals),
    is_correct:score >= 4, signal_delta:1, standards_addressed:'AS-2,HS-6',
    skill_category:'Contextualization'});
}

// ── Signal Monitor: trust signal rating puzzle ─────────────────────
const _sigRatings = {};
const _sigUnearned = ['comprehensive', 'accuracy', 'stamp'];
// stamp is debatable but the key insight is comprehensive + accuracy are unearned

async function rateSig(btn, signal, rating) {
  if(_sigRatings[signal] !== undefined) return;
  _sigRatings[signal] = rating;

  const resultEl = document.getElementById('sigr-' + signal);
  btn.parentElement.querySelectorAll('.sig-rate-btn').forEach(b => {
    b.classList.remove('selected');
    b.disabled = true;
  });
  btn.classList.add('selected');

  const isUnearned = _sigUnearned.includes(signal);
  const correct = (isUnearned && rating === 'unearned') || (!isUnearned && rating === 'earned');

  const explanations = {
    stamp:         { earned: 'A stamp signals verification -- but who verified it, and when?', unearned: 'Correct. A stamp is a formatting choice, not an audit. It cannot verify events that had not yet occurred.' },
    form:          { earned: 'Correct. A formal classification number is administrative metadata -- it confirms the document went through a process.', unearned: 'Form numbers confirm administrative processing -- that is what they can claim.' },
    authority:     { earned: 'Correct. Named authority is a real signal -- but it tells you who produced this, not whether the framing is accurate.', unearned: 'Named authority confirms institutional origin, which is useful provenance information.' },
    comprehensive: { earned: 'Consider: the document lists three source types, all government-produced. "Comprehensive" claims more than that list supports.', unearned: 'Correct. The source list names only government-produced materials. "Comprehensive" is a claim the list cannot support.' },
    accuracy:      { earned: 'Reviewed by whom? Using what criteria? "Accuracy" here is self-asserted.', unearned: 'Correct. "Reviewed for historical accuracy" is self-asserted -- the reviewer is the same institution that produced the exhibit.' },
  };

  if(resultEl) {
    resultEl.textContent = explanations[signal]?.[rating] || '';
    resultEl.style.color = correct ? 'var(--vd)' : 'var(--smon-c)';
    resultEl.style.display = 'block';
    resultEl.style.fontSize = '0.73rem';
    resultEl.style.fontFamily = "'Crimson Pro', serif";
    resultEl.style.marginTop = '0.3rem';
    resultEl.style.fontStyle = 'italic';
  }

  if(Object.keys(_sigRatings).length >= 5 && !S.pro.roleTaskDone) {
    S.pro.roleTaskDone = true;
    const correctCount = Object.entries(_sigRatings)
      .filter(([sig, rat]) => (_sigUnearned.includes(sig) && rat === 'unearned') || (!_sigUnearned.includes(sig) && rat === 'earned')).length;
    const sigResultEl = document.getElementById('signal-result');
    sigResultEl.style.display = 'block';
    sigResultEl.innerHTML =
      `<strong>${correctCount}/5 signals correctly rated.</strong> ` +
      (correctCount >= 4
        ? 'The most powerful signals are the ones that claim completeness and accuracy -- because those are the ones the evidence cannot support.'
        : 'Focus on the signals that claim more than the evidence can prove: comprehensiveness, accuracy, and stamp verification.');
    document.getElementById('btn-mis').style.display = 'inline-block';
    markTask('pt2');
    setSignal(S.signal + 1);
    gainPts(correctCount >= 4 ? 25 : 15, 'Signal audit complete (+' + (correctCount >= 4 ? 25 : 15) + ')', 'analysis');
    showSubmitConfirm(sigResultEl, 'Signal audit submitted', correctCount + '/5 signals correctly rated.');
    await post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
      room:'prologue', task_id:'PROL_SIG_01', task_label:'Trust signal ratings',
      response_type:'multi_rating', response_value:JSON.stringify(_sigRatings),
      is_correct:correctCount >= 4, signal_delta:1, standards_addressed:'AS-4,HS-5',
      skill_category:'Argumentation'});
  }
}

