function buildRoom1(){
  // Apply role frames
  ['lead','evidence','analyst','signal'].forEach(r=>{
    const f=document.getElementById('rf-r1-'+r);
    if(f) f.classList.toggle('visible',r===S.role);
  });
  // Build content area
  const R=ROLES[S.role];
  R.r1Content();
  // Build task list
  const tp=document.getElementById('r1-tasks');
  tp.innerHTML='';
  R.r1Tasks.forEach(t=>{
    tp.insertAdjacentHTML('beforeend',`<div class="task" id="${t.id}"><div class="task-num">${t.id.replace('r1t','TASK 00')}</div><div class="task-desc">${t.desc}</div></div>`);
  });
}

