// ── Ranking mechanic ─────────────────────────────────────────────
let _rankOrder = ['eo9066','wra0043','yamamoto','intake001'];

function rankMove(id, dir) {
  const idx = _rankOrder.indexOf(id);
  const newIdx = idx + dir;
  if(newIdx < 0 || newIdx >= _rankOrder.length) return;
  [_rankOrder[idx], _rankOrder[newIdx]] = [_rankOrder[newIdx], _rankOrder[idx]];
  const list = document.getElementById('rank-list') || document.getElementById('rank-initial');
  if(!list) return;
  const items = Array.from(list.querySelectorAll('.rank-item'));
  items.sort((a,b) => _rankOrder.indexOf(a.dataset.id) - _rankOrder.indexOf(b.dataset.id));
  items.forEach(item => list.appendChild(item));
  _rankOrder.forEach((id, i) => {
    const el = document.getElementById('rn-'+id);
    if(el) el.textContent = i+1;
  });
}

async function submitInitialRanking() {
  const reason = document.getElementById('rank-reason')?.value?.trim();
  if(!reason || reason.length < 15) {
    showToast('Name the feature', 'Describe what made the top item feel trustworthy before proceeding.');
    return;
  }
  // Reveal artifacts
  document.getElementById('lead-artifacts').style.display = 'block';
  document.getElementById('lead-task1-card').classList.add('complete');
  markTask('r1t1');
  setSignal(S.signal + 1);
  gainPts(15, 'Initial trust ranking submitted (+15)', 'action');
  document.getElementById('rank-feedback').style.display = 'block';
  document.getElementById('rank-feedback').innerHTML = 
    '<strong>Ranking recorded.</strong> Now examine the artifacts. See whether your ranking holds after reading.';
  await post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
    room:'room1', task_id:'R1_LEAD_RANK', task_label:'Initial trust ranking',
    response_type:'ranking', response_value:_rankOrder.join('>'), is_correct:true,
    signal_delta:1, standards_addressed:'AS-4,AS-7', skill_category:'Affect Auditing'});
}

// ── Drag-and-drop euphemism decode ───────────────────────────────
function initDragDrop() {
  const chips = document.querySelectorAll('.draggable-chip');
  const zones = document.querySelectorAll('.euph-drop-zone');
  if(!chips.length || !zones.length) return;

  let _selectedChip = null;

  // ── Tap-to-select, tap-to-place (best for mobile) ─────────────
  chips.forEach(chip => {
    chip.addEventListener('click', () => {
      if(parseFloat(chip.style.opacity||1) < 0.5) return; // already placed
      chips.forEach(c => c.classList.remove('selected'));
      if(_selectedChip === chip) { _selectedChip = null; return; }
      _selectedChip = chip;
      chip.classList.add('selected');
    });
  });
  zones.forEach(zone => {
    zone.addEventListener('click', () => {
      if(!_selectedChip) return;
      _applyEuphDrop(zone, _selectedChip.dataset.term);
      _selectedChip.classList.remove('selected');
      _selectedChip = null;
    });
  });

  // ── Mouse drag (desktop) ───────────────────────────────────────
  chips.forEach(chip => {
    chip.addEventListener('dragstart', e => {
      e.dataTransfer.setData('text/plain', chip.dataset.term);
      chip.style.opacity = '0.5';
      chips.forEach(c => c.classList.remove('selected'));
      _selectedChip = null;
    });
    chip.addEventListener('dragend', () => { if(chip.style.opacity === '0.5') chip.style.opacity = '1'; });
  });
  zones.forEach(zone => {
    zone.addEventListener('dragover', e => { e.preventDefault(); zone.classList.add('drag-over'); });
    zone.addEventListener('dragleave', () => zone.classList.remove('drag-over'));
    zone.addEventListener('drop', e => {
      e.preventDefault();
      zone.classList.remove('drag-over');
      _applyEuphDrop(zone, e.dataTransfer.getData('text/plain'));
    });
  });

  // ── Touch drag (mobile) ────────────────────────────────────────
  let _dragChip = null, _ghost = null;
  chips.forEach(chip => {
    chip.addEventListener('touchstart', e => {
      _dragChip = chip; chip.style.opacity = '0.5';
      chips.forEach(c => c.classList.remove('selected')); _selectedChip = null;
      _ghost = chip.cloneNode(true);
      _ghost.style.cssText = 'position:fixed;pointer-events:none;z-index:9999;opacity:0.85;transition:none;font-size:0.85rem;padding:0.3rem 0.6rem;';
      document.body.appendChild(_ghost);
      const t = e.touches[0];
      _ghost.style.left = (t.clientX - 40) + 'px';
      _ghost.style.top  = (t.clientY - 20) + 'px';
    }, {passive:true});
    chip.addEventListener('touchmove', e => {
      e.preventDefault();
      if(!_ghost) return;
      const t = e.touches[0];
      _ghost.style.left = (t.clientX - 40) + 'px';
      _ghost.style.top  = (t.clientY - 20) + 'px';
      zones.forEach(z => z.classList.remove('drag-over'));
      const el = document.elementFromPoint(t.clientX, t.clientY);
      const z2 = el && el.closest('.euph-drop-zone');
      if(z2) z2.classList.add('drag-over');
    }, {passive:false});
    chip.addEventListener('touchend', e => {
      if(_ghost) { _ghost.remove(); _ghost = null; }
      if(!_dragChip) return;
      zones.forEach(z => z.classList.remove('drag-over'));
      const t = e.changedTouches[0];
      const el = document.elementFromPoint(t.clientX, t.clientY);
      const z2 = el && el.closest('.euph-drop-zone');
      if(z2) _applyEuphDrop(z2, _dragChip.dataset.term);
      else _dragChip.style.opacity = '1';
      _dragChip = null;
    }, {passive:true});
  });

  // Mobile hint
  const grid = document.getElementById('euph-grid');
  if(grid && !grid.querySelector('.euph-hint')) {
    const h = document.createElement('div');
    h.className = 'euph-hint';
    h.style.cssText = "font-family:'JetBrains Mono',monospace;font-size:7px;color:var(--sm);letter-spacing:0.08em;text-transform:uppercase;margin-bottom:0.55rem;padding:4px 6px;background:rgba(201,152,42,0.06);border-left:2px solid rgba(201,152,42,0.2);";
    h.textContent = 'Tap a term to select (it highlights), then tap its definition. Or drag and drop.';
    grid.insertBefore(h, grid.firstChild);
  }
}

function _applyEuphDrop(zone, term) {
  const correct = zone.dataset.answer === term;
  zone.classList.remove('drop-correct','drop-wrong');
  zone.classList.add(correct ? 'drop-correct' : 'drop-wrong');
  const chip = document.getElementById('chip-'+term);
  if(chip) {
    if(correct) { chip.style.opacity = '0.3'; chip.draggable = false; chip.classList.remove('selected'); }
    else chip.style.opacity = '1';
  }
  checkAllEuph();
}

let _euphCorrectDnd = {voluntary:false, assembly:false, evacuees:false};
function checkAllEuph() {
  document.querySelectorAll('.euph-drop-zone.drop-correct').forEach(z => {
    _euphCorrectDnd[z.dataset.answer] = true;
  });
  if(Object.values(_euphCorrectDnd).every(Boolean)) {
    earnTrajectoryAction('r1_euph_all_done');
    markTask('r1t2');
    setSignal(S.signal + 1);
    gainPts(30, 'All euphemisms decoded (+30)', 'analysis');
    document.getElementById('euph-ok').style.display = 'block';
    document.getElementById('euph-ok').innerHTML = 
      '<strong>All three decoded.</strong> Official language transforms coercion into administration. Now examine the photograph and unlock the witness accounts.';
    document.getElementById('lead-task2-card').classList.add('complete');
    S.r1.euphDone = true; // ← was missing: drag-drop path never set this
    document.getElementById('witness-drawer').classList.add('ready');
    const _wd1=document.getElementById('witness-drawer');
    _wd1.querySelector('.drawer-icon').textContent='🔓';
    _wd1.querySelector('.drawer-text').textContent='Witness Accounts — ✓ Decoder complete. Click here to access the testimony.';
    _wd1.style.border='1px solid rgba(74,138,114,0.5)';
    _wd1.style.background='rgba(74,138,114,0.08)';
    post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
      room:'room1', task_id:'R1_EUPH_DND', task_label:'Euphemism decode (drag-drop)',
      response_type:'matching', response_value:'voluntary/assembly/evacuees all correct',
      is_correct:true, signal_delta:1, standards_addressed:'AS-1,AS-6', skill_category:'Argumentation'});
  }
}

// ── Photo claim selection ─────────────────────────────────────────
function toggleClaim(el) {
  el.classList.toggle('selected');
  el.querySelector('.claim-check').textContent = el.classList.contains('selected') ? '&#9745;' : '&#9744;';
}

async function submitPhotoClaims() {
  const items = document.querySelectorAll('#photo-claims .claim-item');
  const selected = Array.from(items).filter(i => i.classList.contains('selected'));
  if(selected.length < 2) { showToast('Select more', 'Select at least two claims before submitting.'); return; }

  let correct = 0, incorrect = 0;
  selected.forEach(item => {
    if(item.dataset.verifiable === 'yes') {
      item.style.borderColor = 'rgba(74,138,114,0.5)';
      item.style.background  = 'rgba(74,138,114,0.07)';
      correct++;
    } else {
      item.style.borderColor = 'rgba(192,72,40,0.5)';
      item.style.background  = 'rgba(139,58,42,0.07)';
      incorrect++;
    }
  });

  const fb = document.getElementById('photo-feedback');
  fb.style.display = 'block';
  if(incorrect > 0) {
    fb.innerHTML = `<strong>${incorrect} claim(s) highlighted in red</strong> cannot be verified from the photograph alone -- the caption is asserting them, not the image. The image shows people near vehicles. It cannot show whether they chose to be there.`;
    gainPts(20, 'Photo caption vs. image distinction made (+20)', 'analysis');
  } else {
    fb.innerHTML = '<strong>All selected claims are verifiable.</strong> Notice which claims were left -- those are what the caption adds beyond what the photograph shows.';
    gainPts(25, 'Photo analysis: all correct (+25)', 'analysis');
  }

  markTask('r1t3');
  document.getElementById('lead-task3-card').classList.add('complete');
  if(!document.getElementById('witness-drawer').classList.contains('ready') &&
     Object.values(_euphCorrectDnd).every(Boolean)) {
    S.r1.euphDone = true; // sync state
    document.getElementById('witness-drawer').classList.add('ready');
  const _wd2=document.getElementById('witness-drawer');
  _wd2.querySelector('.drawer-icon').textContent='🔓';
  _wd2.querySelector('.drawer-text').textContent='Witness Accounts — ✓ Analysis complete. Click here to access the testimony.';
  _wd2.style.border='1px solid rgba(74,138,114,0.5)';
  _wd2.style.background='rgba(74,138,114,0.08)';
  } else if(Object.values(_euphCorrectDnd).every(Boolean)) {
    S.r1.euphDone = true; // ensure sync even if drawer already ready
  }
  earnTrajectoryAction('r1_claim_correct');
  await post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
    room:'room1', task_id:'R1_PHOTO_CLAIMS', task_label:'Photo claim verification',
    response_type:'multi_select', response_value:selected.map(i=>i.textContent.trim()).join('|'),
    is_correct:incorrect===0, signal_delta:1, standards_addressed:'AS-4,AS-7,APUSH KC-7.3.III.B',
    skill_category:'Analyzing Evidence'});
}

// ── Final claim scaffold submit ───────────────────────────────────
async function submitLeadClaim() {
  const p1 = document.getElementById('claim-part1')?.value?.trim();
  const p2 = document.getElementById('claim-part2')?.value?.trim();
  const p3 = document.getElementById('claim-part3')?.value?.trim();
  if(!p1 || p1.length < 15) { showToast('Part 1 required','Describe what the official record claims in at least one sentence.'); return; }
  if(!p2 || p2.length < 15) { showToast('Part 2 required','Describe what the testimony reveals -- how it complicates the official record.'); return; }
  if(!p3 || p3.length < 15) { 
    showToast('Limitation required','Part 3 is required: name what this archive cannot prove and why. This is not optional.'); 
    return; 
  }
  const fullClaim = p1 + ' // ' + p2 + ' // LIMITATION: ' + p3;
  document.getElementById('final-input').textContent = fullClaim;
  S.r1.claimSubmitted = true;
  checkVocabBonus(p1 + ' ' + p2 + ' ' + p3, 'room1');
  checkHistoryBonus(p1 + ' ' + p2 + ' ' + p3, 'room1');
  updateRoomProgress('room1');
  document.getElementById('lead-claim-ok').style.display = 'block';
  document.getElementById('lead-claim-ok').innerHTML =
    '<strong>Claim recorded.</strong> Your claim names evidence, challenge, and limit. That is a defensible historical argument. Complete the reflection below to advance to Room 2.';
  document.getElementById('lead-task4-card').classList.add('complete');
  earnTrajectoryAction('limitation_made');
  markTask('r1t5');
  gainPts(40, 'Defensible claim submitted (+40)', 'argumentation');
  // Save all three parts explicitly to Sheets
  await post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, room:'room1', task_id:'R1_LEAD_CLAIM',
    task_label:'Defensible claim -- all three parts',
    response_type:'scaffolded_claim',
    response_value:'OFFICIAL: '+p1+' | TESTIMONY: '+p2+' | LIMIT: '+p3,
    is_correct:true, signal_delta:1,
    standards_addressed:'AS-6,AS-2,HS-1,APUSH KC-7.3.III.B',
    skill_category:'Historical Argumentation'});
  await post({action:'updateDashboard', session_id:S.sessionId, student_name:S.studentName,
    class_period:S.period, role:S.role, current_room:'room1',
    archive_pts:S2.pts, current_rank:S2.rank, signal_score:S.signal,
    rooms_completed:S.roomsComplete, objects_found:Object.keys(S2.inventory).length,
    quests_complete:0, passages_entered:0, loop_count:0,
    hints_used:3-S.hints, locker_count:S.locker.length, status:'active'});
  await recordLimitation('R1_LEAD_CLAIM', fullClaim, p3, 'evidentiary_limit');
  submitR1FinalInternal(fullClaim);
}


async function submitR1FinalInternal(val) {
  if(S.r1.finalDone) return;
  S.r1.finalDone = true;
  S.r1.claimSubmitted = true;
  checkVocabBonus(val, 'room1');
  checkHistoryBonus(val, 'room1');
  markTask('r1t5');
  document.getElementById('lb-a')?.classList.add('open');
  if(document.getElementById('lb-a')) document.getElementById('lb-a').textContent='ok';
  setSignal(5);
  const _claimsByRole = {
    lead:     {historical_claim:val, curation_claim:'', limitation_claim:''},
    evidence: {historical_claim:'', curation_claim:val, limitation_claim:''},
    analyst:  {historical_claim:'', curation_claim:val, limitation_claim:''},
    signal:   {historical_claim:'', curation_claim:'', limitation_claim:val}
  };
  const _claims = _claimsByRole[S.role] || {historical_claim:val, curation_claim:'', limitation_claim:''};
  const _limitSummary = S2.limitationClaims.map(c=>c.limitNamed||c.claimText||'').filter(Boolean).join('; ');
  await post({action:'saveFinal',
    session_id:S.sessionId, student_name:S.studentName, team_name:'',
    role:S.role,
    historical_claim:_claims.historical_claim,
    curation_claim:_claims.curation_claim,
    limitation_claim:_limitSummary || _claims.limitation_claim,
    escape_protocol_q1:_claims.historical_claim,
    escape_protocol_q2:val,
    escape_protocol_q3:_limitSummary||'',
    escape_protocol_q4:'', escape_protocol_q5:'', escape_protocol_q6:'',
    signal_final:S.signal, rooms_completed:S.roomsComplete,
    locker_count:S.locker.length, hints_used:3-S.hints,
    caption_rewrite:'', caption_rewrite_room1:val
  });
  gainPts(40, 'Defensible claim submitted (+40)', 'argumentation');
  showToast('Both Locks Partial', 'Claim recorded. Complete the reflection to advance to Room 2.');
}


async function leadClaimSelect(btn, val){
  if(document.getElementById('lead-claim-ok').style.display==='block') return;
  const isCorrect = val.includes('obscures') || val.includes('coercion');
  document.getElementById('lead-claim-ok').style.display='block';
  document.getElementById('lead-claim-ok').textContent = isCorrect
    ? 'Correct framing. The official language transforms a coercive policy into an administrative procedure. Now decode the specific terms before accessing the testimony.'
    : 'Examine the language more closely. Words like "orderly," "humane," and "evacuees" are doing interpretive work. What do they conceal?';
  if(isCorrect) earnTrajectoryAction('r1_claim_correct');
  markTask('r1t1');
  setSignal(S.signal + (isCorrect?1:0));
  document.getElementById('euph-block').style.display='block';
  await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_LEAD_01',task_label:'Initial claim assessment of EO 9066',response_type:'select',response_value:val,is_correct:isCorrect,signal_delta:isCorrect?1:0,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Argumentation'});
}

