async function evidSaveDoc(){
  const checks=document.querySelectorAll('#evid-r1-checks input:checked');
  if(checks.length===0){showToast('Check at least one','Assess the source type before saving.');return;}
  if(S.r1.provDone) return;
  S.r1.provDone=true;
  const vals=Array.from(checks).map(c=>c.value).join(', ');
  document.getElementById('evid-doc-ok').style.display='block';
  markTask('r1t1');
  setSignal(S.signal+1);
  await saveArt('002','Executive Order 9066 Summary','room1','document','WRA Archives, RG 210 -- public distribution summary');
  await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_EVID_01',task_label:'Provenance check EO summary',response_type:'multi_check',response_value:vals,is_correct:true,signal_delta:1,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Analyzing Evidence'});
}

async function evidCaptionSubmit(){
  const val=document.getElementById('evid-cap-resp').value.trim();
  if(val.length<15){showToast('More detail required','Write your caption analysis -- at least one sentence explaining what you found.');return;}
  if(S.r1.captionFlagged) return;
  S.r1.captionFlagged=true;
  markTask('r1t2');
  setSignal(S.signal+1);
  document.getElementById('witness-drawer').classList.add('ready');
  const _wd3=document.getElementById('witness-drawer');
  _wd3.querySelector('.drawer-icon').textContent='🔓';
  _wd3.querySelector('.drawer-text').textContent='Witness Accounts — ✓ Caption analysis recorded. Click here to access the testimony.';
  _wd3.style.border='1px solid rgba(74,138,114,0.5)';
  _wd3.style.background='rgba(74,138,114,0.08)';
  document.getElementById('witness-drawer').querySelector('.drawer-text').textContent='Witness Accounts — ✓ Caption analysis recorded. Click here to access the testimony. The testimony was collected by the Japanese American Evacuation and Resettlement Study, UC Berkeley. Click to unlock.';
  showToast('Caption Analyzed','Witness drawer now ready to unlock.');
  const vc=document.getElementById('vc-r1');
  if(vc) vc.innerHTML='<div class="voice-flag">Non-WRA testimony -- different institution, different chain of custody</div>';
  await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_EVID_02',task_label:'Caption provenance analysis',response_type:'long_text',response_value:val,is_correct:true,signal_delta:1,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Analyzing Evidence'});
}

