function buildCatMapRow(letter, label){
  return `<div style="display:flex;align-items:center;gap:0.5rem;flex-wrap:wrap;">
    <span style="font-family:'JetBrains Mono',monospace;font-size:8px;color:var(--anal-c);letter-spacing:0.1em;min-width:18px;">${letter}</span>
    <span style="font-family:'Crimson Pro',serif;font-size:0.8rem;color:var(--pd);flex:1;min-width:160px;">${label}</span>
    <select class="arch-select" style="min-width:140px;font-size:0.78rem;padding:0.25rem 0.4rem;" data-cat="${letter}">
      <option value="">Classify...</option>
      <option value="present">Present</option>
      <option value="absent">Absent</option>
      <option value="structural">Structurally excluded</option>
    </select>
  </div>`;
}

async function submitCatMap(){
  if(S.r1.analystMapDone) return;
  const selects=document.querySelectorAll('#cat-map select');
  const all=Array.from(selects).every(s=>s.value!=='');
  if(!all){showToast('Incomplete map','Classify all five source categories before submitting.');return;}
  const vals={};
  selects.forEach(s=>vals[s.dataset.cat]=s.value);
  const cIsExcluded = vals['C']==='absent'||vals['C']==='structural';
  if(!cIsExcluded){showToast('Reconsider Category C','First-person testimony: is it simply absent, or was the archive not designed to include it at all?');return;}
  S.r1.analystMapDone=true;
  document.getElementById('cat-map-ok').style.display='block';
  document.getElementById('anal-artifacts').style.display='block';
  markTask('r1t1');
  setSignal(S.signal+1);
  const vc=document.getElementById('vc-r1');
  if(vc) vc.innerHTML='<div class="voice-flag">Category C -- first-person testimony -- structurally excluded</div><div class="voice-flag">Categories D, E -- independent press, legal petitions -- absent</div>';
  await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_ANAL_01',task_label:'Source category map',response_type:'multi_select',response_value:JSON.stringify(vals),is_correct:cIsExcluded,signal_delta:1,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Contextualization'});
}

async function submitAnalWhy(){
  const val=document.getElementById('anal-why-input').value.trim();
  if(val.length<20){showToast('More detail required','Describe the structural absence in at least one sentence.');return;}
  if(S.r1.captionFlagged) return;
  S.r1.captionFlagged=true;
  markTask('r1t2');
  markTask('r1t3');
  setSignal(S.signal+1);
  const _wd = document.getElementById('witness-drawer');
  _wd.classList.add('ready');
  _wd.querySelector('.drawer-icon').textContent = '🔓';
  _wd.querySelector('.drawer-text').textContent = 'Witness Accounts — Category C. ✓ Structural analysis recorded. Click here to access the testimony.';
  _wd.style.animation = 'none';
  _wd.style.border = '1px solid rgba(74,138,114,0.5)';
  _wd.style.background = 'rgba(74,138,114,0.08)';
  await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_ANAL_02',task_label:'Why does absence feel like completeness',response_type:'long_text',response_value:val,is_correct:true,signal_delta:1,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Contextualization'});
}

