// ROOM 1 -- SIGNAL MONITOR PATH
// ========================================================
function buildSignalRoom1(){
  document.getElementById('r1-content').innerHTML=`
    <div class="art-label">Trust Signal Audit -- Rate each artifact before engaging with content</div>
    <div class="sig-audit visible" id="sig-audit-r1">
      <div style="font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.12em;color:var(--smon-c);text-transform:uppercase;margin-bottom:0.6rem;">Signal Monitor -- Affective authority audit</div>
      <div style="font-family:'Crimson Pro',serif;font-size:0.83rem;color:var(--pd);margin-bottom:0.7rem;font-style:italic;">For each artifact below, rate its trust signals before reading for content. Signals are: Formal Design, Named Authority, Claim of Completeness, Claim of Neutrality, Administrative Order. Rate each: Earned (the signal is backed by evidence) or Unearned (the signal exceeds what the evidence supports).</div>
      <div class="sa-row">
        <div class="sa-doc"><strong>EO 9066 Summary</strong><br>"orderly and humane manner" -- "comprehensive" -- WRA official seal -- Form number</div>
        <div class="sa-controls">
          <button class="sa-btn trust" onclick="sigRate(this,'002','earned','The administrative signals are consistent with the document type.')">Earned</button>
          <button class="sa-btn reject" onclick="sigRate(this,'002','unearned','The signals of order and completeness exceed what a one-page summary can prove.')">Unearned</button>
        </div>
        <div class="sa-result" id="sigr-002">--</div>
      </div>
      <div class="sa-row" style="margin-top:0.7rem;">
        <div class="sa-doc">
          <strong>Photograph WRA-0043</strong>
          <div style="margin:0.45rem 0 0.4rem;">
            <div class="photo-frame" style="max-width:420px;">
              <img src="img/img07.jpg"
                   alt="Manzanar War Relocation Center, 1942. Japanese American families carrying belongings in dust. Barracks and Sierra Nevada mountains in background."
                   style="width:100%;display:block;filter:sepia(0.1) contrast(1.04);">
            </div>
          </div>
          Institutional label -- official caption -- "voluntary" -- "cooperative assistance program"
          <div style="margin-top:0.5rem;">
            <div style="font-family:'JetBrains Mono',monospace;font-size:7px;color:var(--smon-c);letter-spacing:0.1em;text-transform:uppercase;margin-bottom:0.3rem;">Second WRA photograph for comparison</div>
            <div class="photo-frame" style="max-width:420px;">
              <img src="img/img08.jpg"
                   alt="Manzanar War Relocation Center, 1942. Three Japanese American women in foreground, barracks under construction in background. Mountains visible."
                   style="width:100%;display:block;filter:sepia(0.12) contrast(1.03);">
            </div>
            <div style="font-family:'Crimson Pro',serif;font-size:0.75rem;color:var(--sm);font-style:italic;margin-top:0.3rem;">WRA official caption: "Residents of Manzanar, spring 1942." Compare the affect of this photograph to WRA-0043. What trust work does each do differently?</div>
          </div>
        </div>
        <div class="sa-controls">
          <button class="sa-btn trust" onclick="sigRate(this,'wra-photo','earned','The photographic record is an accurate reflection of events.')">Earned</button>
          <button class="sa-btn reject" onclick="sigRate(this,'wra-photo','unearned','The caption language attributes voluntary choice to a coerced removal.')">Unearned</button>
        </div>
        <div class="sa-result" id="sigr-photo">--</div>
      </div>
      <div id="sig-audit-ok" style="display:none;margin-top:0.65rem;background:rgba(160,104,48,0.08);border:0.5px solid rgba(160,104,48,0.28);padding:0.55rem;font-family:'Crimson Pro',serif;font-size:0.78rem;color:var(--smon-c);">Trust signal audit recorded. Now examine what feeling the calmness of this archive as a whole produces -- and then ask whether that feeling was earned.</div>
    </div>
    <div id="sig-deep" style="display:none;">
      <div class="art-label" style="margin-top:0.5rem;">Affective audit -- The archive as a whole</div>
      <div style="max-width:560px;background:rgba(24,18,12,0.55);border:0.5px solid rgba(160,104,48,0.2);padding:0.8rem;margin-bottom:0.8rem;">
        <div style="font-family:'Crimson Pro',serif;font-size:0.83rem;color:var(--pd);margin-bottom:0.55rem;font-style:italic;">An archive that is sparse, officially labeled, and well-organized produces a specific feeling. Name that feeling, then name the formal features producing it, then ask whether those features are evidence of completeness or evidence of curation.</div>
        <textarea class="arch-textarea" id="sig-affect-input" placeholder="Name the feeling. Name the features. Ask whether they are earned..." style="min-height:65px;"></textarea>
        <button class="btn-task" style="margin-top:0.4rem;" onclick="submitSigAffect()">Submit affective audit</button>
      </div>
      <div class="drawer" id="witness-drawer" onclick="unlockWitness()">
        <div class="drawer-icon">&#128274;</div>
        <div class="drawer-text">Witness Accounts -- The testimony was not produced by the WRA. Its affect is different. Submit your affective audit to unlock and compare.</div>
      </div>
      <div class="testimony" id="testimony-r1">${testimonyHTML()}</div>
      <div class="rewrite-block" id="rewrite-r1">
        <div class="art-label">Signal Monitor -- Signal report</div>
        <div style="font-family:'Crimson Pro',serif;font-size:0.83rem;color:var(--pd);margin-bottom:0.55rem;font-style:italic;">Write a signal report: which features of this archive produced the strongest trust effects? Which were earned by the evidence, and which were produced by design? How did the affect of the testimony differ from the official record -- and what does that difference reveal about how archives construct authority?</div>
        <textarea class="arch-textarea" id="final-input" placeholder="Your signal report..."></textarea>
        <button class="btn-gold" style="font-size:0.76rem;padding:0.48rem 1.1rem;margin-top:0.4rem;" onclick="submitR1Final()">Submit signal report</button>
      </div>
    </div>
    <div class="reflect" id="reflect-r1" style="display:none;">${reflectHTML('r1')}</div>
  `;
}

let sigRatesDone=0;
async function sigRate(btn, id, rating, reason){
  const resultEl=document.getElementById('sigr-'+id);
  if(resultEl && resultEl.textContent!=='--') return;
  if(resultEl) resultEl.textContent=rating==='earned'?'Earned':'Unearned';
  sigRatesDone++;
  const isCorrect=(id==='002'&&rating==='unearned')||(id==='wra-photo'&&rating==='unearned');
  setSignal(S.signal+(isCorrect?0.5:0));
  showToast('Signal Rated', reason);
  if(sigRatesDone>=2 && !S.r1.signalAuditDone){
    S.r1.signalAuditDone=true;
    document.getElementById('sig-audit-ok').style.display='block';
    document.getElementById('sig-deep').style.display='block';
    markTask('r1t1');
    markTask('r1t2');
  }
  await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_SIG_'+id,task_label:'Trust signal rating: '+id,response_type:'select',response_value:rating,is_correct:isCorrect,signal_delta:isCorrect?0.5:0,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Argumentation'});
}

async function submitSigAffect(){
  const val=document.getElementById('sig-affect-input').value.trim();
  if(val.length<20){showToast('More detail required','Describe the affect and whether it was earned -- at least one sentence.');return;}
  if(S.r1.captionFlagged) return;
  S.r1.captionFlagged=true;
  markTask('r1t3');
  setSignal(S.signal+1);
  document.getElementById('witness-drawer').classList.add('ready');
  const _wd4=document.getElementById('witness-drawer');
  _wd4.querySelector('.drawer-icon').textContent='🔓';
  _wd4.querySelector('.drawer-text').textContent='Witness Accounts — ✓ Affective audit recorded. Click here to access the testimony.';
  _wd4.style.border='1px solid rgba(74,138,114,0.5)';
  _wd4.style.background='rgba(74,138,114,0.08)';
  await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_SIG_02',task_label:'Affective audit of archive as whole',response_type:'long_text',response_value:val,is_correct:true,signal_delta:1,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Argumentation'});
}

