function buildEuphRows(){
  return `
    <div class="euph-row">
      <div class="euph-term">"Voluntary relocation"</div><div class="euph-arr">to</div>
      <select class="euph-sel" id="es1" onchange="checkEuph(this,1)">
        <option value="">Select...</option>
        <option value="w">Cooperative migration program</option>
        <option value="c">Forced removal under military order</option>
        <option value="w">Wartime resettlement initiative</option>
      </select>
    </div>
    <div class="euph-row">
      <div class="euph-term">"Assembly center"</div><div class="euph-arr">to</div>
      <select class="euph-sel" id="es2" onchange="checkEuph(this,2)">
        <option value="">Select...</option>
        <option value="w">Civilian processing facility</option>
        <option value="c">Detention facility, often called a concentration camp</option>
        <option value="w">Defense housing installation</option>
      </select>
    </div>
    <div class="euph-row">
      <div class="euph-term">"Evacuees"</div><div class="euph-arr">to</div>
      <select class="euph-sel" id="es3" onchange="checkEuph(this,3)">
        <option value="">Select...</option>
        <option value="c">Imprisoned American citizens and residents</option>
        <option value="w">Wartime voluntary participants</option>
        <option value="w">Relocated community members</option>
      </select>
    </div>
    <div class="puzzle-ok" id="euph-ok"></div>
  `;
}

async function checkEuph(el,n){
  if(el.value==='c'){
    el.classList.add('correct');el.classList.remove('wrong');
    if(!S.r1.euphCorrect[n-1]){
      S.r1.euphCorrect[n-1]=true;euphCount++;
      setSignal(S.signal+0.5);
      await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_003_'+n,task_label:'Decode euphemism '+n,response_type:'select',response_value:el.options[el.selectedIndex].text,is_correct:true,signal_delta:0.5,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Argumentation'});
    }
  } else if(el.value==='w'){
    el.classList.add('wrong');el.classList.remove('correct');
    showToast('Noise Detected','That framing accepts the archive\'s own terms. Try again.');
  }
  if(euphCount>=3&&!S.r1.euphDone){
    S.r1.euphDone=true;
    const ok=document.getElementById('euph-ok');
    if(ok){ok.style.display='block';ok.textContent='All three decoded. Official language makes violence sound like administration. Now unlock the witness accounts.';}
    markTask('r1t3');
    document.getElementById('witness-drawer').classList.add('ready');
    const _wd5=document.getElementById('witness-drawer');
    _wd5.querySelector('.drawer-icon').textContent='🔓';
    _wd5.querySelector('.drawer-text').textContent='Witness Accounts — ✓ Language decoded. Click here to unlock the testimony.';
    _wd5.style.border='1px solid rgba(74,138,114,0.5)';
    _wd5.style.background='rgba(74,138,114,0.08)';
  }
}

function testimonyHTML(){
  return `
    <div style="background:#f0e8d0;border:0.5px solid rgba(106,80,48,0.3);padding:0.6rem;max-width:580px;margin-bottom:0.6rem;">
      <div style="font-family:'JetBrains Mono',monospace;font-size:6.5px;color:#6a5030;text-transform:uppercase;letter-spacing:0.12em;margin-bottom:0.4rem;">Also in this archive &mdash; not in the WRA exhibit</div>
      <img src="img/img09.jpg"
           alt="Loyalty questionnaire Questions 25-28. Question 27: willing to serve in armed forces? Question 28: swear allegiance to the United States and forswear allegiance to Japanese emperor?"
           style="width:100%;display:block;filter:sepia(0.05);">
      <div style="font-family:'JetBrains Mono',monospace;font-size:6px;color:#6a5030;padding:3px 0;">Questions 27 and 28 &mdash; War Relocation Authority Loyalty Questionnaire, 1943 &mdash; required of all incarcerated Japanese Americans over 17</div>
    </div>
    <div style="background:#f0e8d0;border-left:4px solid #8a6830;padding:1rem 1.3rem;max-width:580px;font-family:'Crimson Pro',serif;">
      <div style="font-family:'JetBrains Mono',monospace;font-size:6.5px;letter-spacing:0.14em;color:#6a5030;text-transform:uppercase;margin-bottom:0.55rem;padding-bottom:0.4rem;border-bottom:0.5px solid rgba(106,80,48,0.25);">
        Witness Account &mdash; Japanese American Evacuation and Resettlement Study (JERS)<br>
        University of California, Berkeley &mdash; Collected 1942&ndash;1945 &mdash; Restricted until 1976<br>
        Source: Bancroft Library, BANC MSS 67/14 c &mdash; Composite drawn from interviews conducted by Charles Kikuchi
      </div>
      <p style="font-size:0.88rem;color:#2a1e10;line-height:1.75;margin-bottom:0.6rem;">
        &ldquo;They told us we had forty-eight hours. My father had a nursery on the peninsula &mdash; twenty-two years of work. He sold the entire inventory for $35. We were allowed two suitcases each. My mother wrapped her dishes in newspaper but then put them back. There was no room.
      </p>
      <p style="font-size:0.88rem;color:#2a1e10;line-height:1.75;margin-bottom:0.6rem;">
        They called us <em>evacuees</em>. I learned later that word was chosen deliberately. The WRA style guide specified it. An evacuee is someone protected, moved for their own safety. We were not evacuees.&rdquo;
      </p>
      <div style="font-size:0.76rem;color:#5a4a2a;font-style:italic;border-top:0.5px solid rgba(106,80,48,0.2);padding-top:0.4rem;margin-top:0.3rem;">
        JERS interviewers were themselves Japanese American; several were incarcerated at Gila River and Tule Lake. Interviews were conducted in English and Japanese. Charles Kikuchi&rsquo;s diary (also BANC MSS 67/14 c) provides parallel documentation.
        <br><strong>Note:</strong> This source category &mdash; first-person testimony from incarcerated individuals &mdash; does not appear in the WRA&rsquo;s own exhibit materials.
      </div>
    </div>

    <!-- Active task: testimony comparison questions -->
    <div class="task-card" style="max-width:580px;margin-top:0.7rem;">
      <div class="task-card-hdr">
        <div class="task-card-num">TESTIMONY TASK</div>
        <div class="task-card-title">What does this source reveal that the official record cannot?</div>
        <div class="task-card-std">HS-1 Multiperspectivity &nbsp;&middot;&nbsp; AS-7 Relational Reading</div>
      </div>
      <div class="task-card-body">
        <p class="task-instruction" style="margin-bottom:0.6rem;">Answer all three questions. Your responses are saved to your evidence locker.</p>

        <div class="scaffold-row" style="margin-bottom:0.55rem;">
          <div class="scaffold-label">What does the WRA record call this process? What does the witness call it?</div>
          <textarea class="arch-textarea" id="testy-q1" placeholder="Name both terms and what each term does..." style="min-height:42px;"></textarea>
        </div>

        <div class="scaffold-row" style="margin-bottom:0.55rem;">
          <div class="scaffold-label">The WRA had a style guide that specified the word &ldquo;evacuee.&rdquo; What does that tell you about the caption for Photograph WRA-0043?</div>
          <textarea class="arch-textarea" id="testy-q2" placeholder="Was the caption language accidental or chosen?" style="min-height:42px;"></textarea>
        </div>

        <div class="scaffold-row" style="margin-bottom:0.55rem;">
          <div class="scaffold-label">Rate: on a scale of 1&ndash;5, how much does this testimony change your confidence in the official record? (1 = no change, 5 = changes everything)</div>
          <div style="display:flex;gap:0.5rem;flex-wrap:wrap;margin-top:0.3rem;">
            ${[1,2,3,4,5].map(n=>`<button class="sig-rate-btn" id="testy-scale-${n}" onclick="setTestimonyScale(${n})">${n}</button>`).join('')}
          </div>
          <div id="testy-scale-result" style="font-family:'Crimson Pro',serif;font-size:0.88rem;color:var(--vd);font-style:italic;margin-top:0.5rem;line-height:1.55;display:none;padding:0.4rem 0.6rem;background:rgba(74,138,114,0.08);border-left:2px solid var(--vd);"></div>
        </div>

        <button class="btn-task" style="margin-top:0.3rem;" onclick="submitTestimonyTask()">Save testimony analysis</button>
        <div id="testy-task-ok" class="task-feedback" style="display:none;">Testimony analysis saved. Now construct your defensible claim using both the official record and this testimony.</div>
      </div>
    </div>`;
}

let _testimonyScale = 0;
function setTestimonyScale(n) {
  _testimonyScale = n;
  [1,2,3,4,5].forEach(i => {
    const btn = document.getElementById('testy-scale-'+i);
    if(btn) btn.classList.toggle('selected', i===n);
  });
  updateRoomProgress('room1');
  const result = document.getElementById('testy-scale-result');
  if(result) {
    const msgs = {
      1: "What in the official record made you so certain that this does not move you?",
      2: "What would the testimony need to say to move your confidence further?",
      3: "Name what you are still uncertain about. That uncertainty is evidence.",
      4: "Name what specifically changed. Was it the content or the register -- the affect -- of the account?",
      5: "Be careful: does a single testimony overturn the official record, or does it reframe the question you need to ask of it?"
    };
    result.textContent = msgs[n] || '';
    result.style.display = 'block';
  }
}

async function submitTestimonyTask() {
  const q1 = document.getElementById('testy-q1')?.value?.trim();
  const q2 = document.getElementById('testy-q2')?.value?.trim();
  if(!q1 || q1.length < 15) { showToast('More detail required','Answer question 1 in at least one sentence before saving.'); return; }
  if(!q2 || q2.length < 15) { showToast('More detail required','Answer question 2 in at least one sentence before saving.'); return; }
  if(!_testimonyScale) { showToast('Required', 'Rate your confidence change on the 1-5 scale.'); return; }
  checkVocabBonus(q1 + ' ' + q2, 'room1');
  checkHistoryBonus(q1 + ' ' + q2, 'room1');
  document.getElementById('testy-task-ok').style.display = 'block';
  markTask('r1t4');
  gainPts(25, 'Testimony analysis complete (+25)', 'analysis');
  // Show the final claim section
  const rewrite = document.getElementById('rewrite-r1');
  if(rewrite) rewrite.style.display = 'block';
  await post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
    room:'room1', task_id:'R1_TESTY_TASK', task_label:'Testimony comparison task',
    response_type:'multi_response',
    response_value: q1 + ' | ' + q2 + ' | scale:' + _testimonyScale,
    is_correct:true, signal_delta:1,
    standards_addressed:'HS-1,AS-7,HS-5',
    skill_category:'Multiperspectivity'});
}


function reflectHTML(room){
  const prompts={
    r1: {
      lead: ['What made the official language feel trustworthy before you decoded it? What in you wanted to trust it? What would you have claimed if you had stopped before reaching the testimony -- and what would have stayed invisible?', 'What changed about what you could claim once the testimony became available? And what does it mean that the testimony was not in the official archive -- that you needed a different institution, decades later, to access it?'],
      evidence: ['What did checking provenance before content change about how you read the documents? What did you notice that a reader who started with content might have missed? And: was there a moment when you wanted to skip the provenance check and just read? What produced that desire?', 'What does it mean for the Lead Auditor\'s final claim that you chose certain artifacts to save and not others? Name one thing you chose not to save -- and ask whether that choice was a method or a convenience.'],
      analyst: ['What changed in how you read the documents once you had already named the missing categories? Did the presence of testimony confirm your map or surprise you? At what point, if any, did the absence start to feel normal -- and what produced that normalization?', 'Why would a well-funded, well-organized official archive be structured to exclude category C? What does that tell you about who the archive was for -- and about what you, entering it as a student with a task to complete, were designed to notice and designed to miss?'],
      signal: ['Before you had words for the mechanism, did the calmness of this archive affect your sense of its completeness? When did you first notice that feeling? And: what would it have taken for you not to notice it -- for the design to have worked completely?', 'How did the affect of the testimony differ from the official record? What produced that difference? And: which of the two felt more like evidence to you -- and why? Ask whether that feeling was earned, or whether it was produced by something the design of each document was doing before you read a single word.']
    }
  };
  const ps=prompts[room][S.role]||prompts[room].lead;
  return `<div class="art-label" style="margin-bottom:0.55rem;">Room Reflection -- Required before Room 2</div>
    <div class="rp">${ps[0]}</div>
    <textarea class="arch-textarea" id="ref-1" placeholder="Your response..." style="margin-bottom:0.65rem;"></textarea>
    <div class="rp">${ps[1]}</div>
    <textarea class="arch-textarea" id="ref-2" placeholder="Your response..." style="margin-bottom:0.65rem;"></textarea>
    <button class="btn-gold" style="font-size:0.76rem;padding:0.5rem 1.1rem;" onclick="completeRoom1()">Advance to Room 2</button>`;
}

async function unlockWitness(){
  if(S.r1.witnessUnlocked) return;
  const drawer=document.getElementById('witness-drawer');
  if(!drawer.classList.contains('ready')&&S.role!=='lead') return;
  // for lead: require euph done -- check both paths (DnD and select)
  const _dndDone = typeof _euphCorrectDnd !== 'undefined' && Object.values(_euphCorrectDnd).every(Boolean);
  const _euphReadyAny = S.r1.euphDone || _dndDone || drawer.classList.contains('ready');
  if(S.role==='lead' && !_euphReadyAny){
    showToast('Decode First','Complete the euphemism decoder before accessing the testimony.');
    return;
  }
  // Sync euphDone so future checks pass
  if(_dndDone) S.r1.euphDone = true;
  S.r1.witnessUnlocked=true;
  drawer.style.display='none';
  const t=document.getElementById('testimony-r1');
  if(t) t.classList.add('visible');
  const rw=document.getElementById('rewrite-r1');
  if(rw) rw.classList.add('visible');
  // show reflect for analyst/signal (they have it hidden initially)
  const ref=document.getElementById('reflect-r1');
  if(ref) ref.classList.add('visible');
  document.getElementById('lb-h').classList.add('open');
  document.getElementById('lb-h').textContent='ok';
  setSignal(4);
  markTask('r1t4');
  await saveArt('testimony','Yamamoto Family Testimony, 1943','room1','testimony','JERS, UC Berkeley 1943, declassified 1976');
  const vc=document.getElementById('vc-r1');
  if(vc&&!vc.querySelector('.voice-flag')) vc.innerHTML='<div class="voice-flag">Japanese American first-person testimony -- absent from official WRA record</div>';
  showModal('Archive Lock Partial -- Room I','The Voice That Was Not Filed',
    'Witness accounts from the people who were incarcerated do not appear in the WRA exhibit record. The archive contains memoranda, maps, and photographs -- all produced by the administrative apparatus of incarceration itself. The people most affected by the policy are legible only in administrative categories: "evacuees," "residents," "persons of Japanese ancestry." They do not speak. They are spoken of. The materials were collected -- eventually -- but not by the WRA. A different institution, decades later, made them available.',
    'What is absent from an archive is not simply missing. It reflects whose voice the archive was designed to include.'
  );
  await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_004',task_label:'Unlock witness accounts',response_type:'identification',response_value:'Witness drawer unlocked: student identified missing category and accessed JERS testimony',is_correct:true,signal_delta:1,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Contextualization'});
}

async function submitR1Final(){
  const val=document.getElementById('final-input').value.trim();
  if(val.length<25){showToast('More detail required','Write a fuller response before submitting -- at least two sentences.');return;}
  if(S.r1.finalDone) return;
  S.r1.finalDone=true;
  markTask('r1t5');
  document.getElementById('lb-a').classList.add('open');
  document.getElementById('lb-a').textContent='ok';
  earnTrajectoryAction('both_locks_open');
  setSignal(5);
  // Show the Next Room button in the header bar
  const nextBtn = document.getElementById('hdr-next-r1');
  if(nextBtn) nextBtn.classList.add('visible');
  // Also mark the lock item as unlocked
  document.querySelectorAll('.lb-item').forEach(el => el.classList.add('unlocked'));
  document.getElementById('final-input').insertAdjacentHTML('afterend',`
    <div style="background:rgba(74,138,114,0.12);border:1px solid rgba(74,138,114,0.35);padding:0.75rem 0.9rem;margin-top:0.6rem;">
      <div style="font-family:'Crimson Pro',serif;font-size:0.88rem;color:var(--vd);margin-bottom:0.6rem;line-height:1.55;">
        &#10003; Response saved. Both room locks are open.<br>
        <span style="color:var(--pa);">Complete the reflection below, then use the <strong style="color:var(--go);">Room 2 → button in the top bar</strong> to advance.</span>
      </div>
      <button onclick="completeRoom1()" style="background:var(--go);color:#0e1a0e;border:none;font-family:'IM Fell English SC',serif;font-size:0.88rem;letter-spacing:0.08em;padding:0.5rem 1.4rem;cursor:pointer;width:100%;">
        &#10003; Complete reflection &amp; advance to Room 2 &rarr;
      </button>
    </div>`);
  const finalLabels={lead:'Defensible historical claim',evidence:'Locker summary',analyst:'Structural analysis report',signal:'Signal report'};
  await post({action:'saveResponse',session_id:S.sessionId,student_name:S.studentName,room:'room1',task_id:'R1_005',task_label:finalLabels[S.role]||'Final response',response_type:'long_text',response_value:val,is_correct:true,signal_delta:1,standards_addressed:'APUSH KC-7.3.III.B',skill_category:'Argumentation'});
  // Build role-specific claim fields for saveFinal
  const _claimsByRole = {
    lead:     {historical_claim:val, curation_claim:'', limitation_claim:''},
    evidence: {historical_claim:'', curation_claim:val, limitation_claim:''},
    analyst:  {historical_claim:'', curation_claim:val, limitation_claim:''},
    signal:   {historical_claim:'', curation_claim:'', limitation_claim:val}
  };
  const _claims = _claimsByRole[S.role] || {historical_claim:val, curation_claim:'', limitation_claim:''};
  // Pull reflection responses if available
  const _ref1 = document.getElementById('ref-1')?.value?.trim() || '';
  const _ref2 = document.getElementById('ref-2')?.value?.trim() || '';
  // Build limitation summary from tracked claims
  const _limitSummary = S2.limitationClaims.map(c=>c.limitNamed||c.claimText||'').filter(Boolean).join('; ');
  await post({action:'saveFinal',
    session_id:S.sessionId, student_name:S.studentName, team_name:'',
    role:S.role,
    historical_claim:_claims.historical_claim,
    curation_claim:_claims.curation_claim,
    limitation_claim:_limitSummary || _claims.limitation_claim,
    escape_protocol_q1:_ref1,
    escape_protocol_q2:_ref2,
    escape_protocol_q3:'',
    escape_protocol_q4:'',
    escape_protocol_q5:S2.handoffDecision ? S2.handoffDecision.decision+': '+S2.handoffDecision.reasoning : '',
    escape_protocol_q6:S2.unarchivableMarkers.map(m=>m.text).join('; '),
    signal_final:S.signal,
    rooms_completed:S.roomsComplete,
    locker_count:S.locker.length,
    hints_used:3-S.hints,
    caption_rewrite:'',
    caption_rewrite_room1:val
  });
  // v3: check if limitation clause is present in the claim
  const hasLimitation = val.toLowerCase().includes('cannot') ||
    val.toLowerCase().includes('cannot claim') ||
    val.toLowerCase().includes('limited') ||
    val.toLowerCase().includes('unclear') ||
    val.toLowerCase().includes('without') ||
    val.toLowerCase().includes('but not');
  if(hasLimitation) {
    gainPts(20, 'Limitation clause detected in final claim (+20)', 'limitation');
    await recordLimitation('R1_005', val, 'embedded in claim', 'evidentiary_limit');
    showToast('Limitation Claim Recorded', 'Your claim names what it cannot say. That is part of responsible historical practice, not a bonus to it.');
  } else {
    showToast('Claim Submitted','Response recorded. Complete the reflection to advance. Before you do: consider whether your claim names what it cannot prove. A claim without a named limit is a claim that has not fully accounted for its evidence.');
  }
}

async function completeRoom1(){
  // Gate 1: claim must be submitted first
  if(!S.r1.claimSubmitted) {
    showToast('Claim required','Complete and save your historical claim before advancing. Scroll up to the claim task.');
    return;
  }
  const r1=document.getElementById('ref-1') ? document.getElementById('ref-1').value.trim() : '';
  const r2=document.getElementById('ref-2') ? document.getElementById('ref-2').value.trim() : '';
  if(r1.length<15||r2.length<15){showToast('Reflection required','Please write a response to both reflection prompts before advancing to Room 2.');return;}
  // v3 constitutive check: limitation claim required before Room 2
  if(S2.limitationClaims.length === 0) {
    const preLimit = await promptUser('Limitation Claim Required',
      'Before you advance: name one thing this archive cannot prove -- not one thing you did not find, but one thing the evidence structurally cannot support. What remains outside the boundary of your claim? This is part of the historical method, not a supplement to it.');
    if(!preLimit || preLimit.length < 10) {
      showToast('Limitation Required', 'Name what your evidence cannot prove before advancing. This is part of the method, not a bonus.');
      return;
    }
    await recordLimitation('R1_GATE', '', preLimit, 'advance_gate');
  }
  S.r1.reflectionDone=true;
  S.roomsComplete=1;
  S.principles.push('What is shown was chosen. Calmness can do ideological work.');

  // Role-specific principle addendum
  const addenda={
    evidence:'The chain of custody is itself evidence about how archives make decisions.',
    analyst:'What is absent from an archive is not simply missing. It reflects whose voice the archive was designed to include.',
    signal:'Trust signals can exceed what the evidence they attach to actually supports. Feeling is not proof.'
  };
  if(addenda[S.role]) S.principles.push(addenda[S.role]);

  // Set role-specific completion text
  const bridges={
    lead:'In Room 2, you will have more to assess. The question is not whether you can make a claim -- it is what conditions make a claim possible, and whether those conditions change.',
    evidence:'In Room 2, you will face a different kind of provenance problem. When sources multiply and circulate, tracing the chain of custody becomes a different kind of labor.',
    analyst:'In Room 2, the absence problem changes shape. There is no longer a sparse archive. There is a very full one. But fullness is not the same as completeness.',
    signal:'In Room 2, the trust signals change. Visibility and volume produce different feelings from order and scarcity. Your task is the same: name the signals before you assess the content.'
  };
  document.getElementById('r1-principle-body').textContent='Calmness can do ideological work. Authority plus order can create false completeness. The absence of a source category is not an oversight -- it is a decision.';
  document.getElementById('r1-bridge').textContent=bridges[S.role]||bridges.lead;

  await post({action:'saveReflection',session_id:S.sessionId,student_name:S.studentName,room:'room1',
    prompt_1:ROLES[S.role].r1Tasks.slice(-2)[0]?.desc||'',response_1:r1,
    prompt_2:ROLES[S.role].r1Tasks.slice(-1)[0]?.desc||'',response_2:r2});
  // v3: smoothness check before advancing
  await showSmoothnessCheck('room1');
  // v3: role shift prompt
  const roleShiftResp = await promptUser('Role in the Historical Process',
    'You have just made a claim about a historical record. Name your actual function -- not your audit title, but what you did. Did you filter? Select? Confirm? Exclude? Refuse? Then ask: what in this archive made it easy to stop asking? What in you wanted to stop?');
  if(roleShiftResp) {
    await recordRoleShift('reader', roleShiftResp, 'End of Room 1');
  }
  // v3: limitation claim prompt (Room 1 final output)
  const limitResp = await promptUser('Limitation Claim',
    'Before you advance: name one thing your evidence cannot prove. What remains outside the claim you just wrote?');
  if(limitResp && limitResp.length > 10) {
    await recordLimitation('R1_005', '', limitResp, 'evidentiary_limit');
  }
  await post({action:'updateSession',session_id:S.sessionId,current_room:'room2',rooms_completed:1});
  // v3: offer parallel endings if any trajectory action has been earned
  // (paths form from Room 1 onward, not gated on points)
  if((computeTrajectories().length > 0 || S3.trajectoryActions.has('both_locks_open')) && !S2.endingPath) {
    await showEndingChooser();
  }
  syncDashboard();
  goTo('screen-r1-complete');
}

