// ── Room progress checklist helpers ─────────────────────────────────
// Updates the "Before you advance" checklist inside each room

function updateRoomProgress(room) {
  const el = document.getElementById('progress-' + room);
  if(!el) return;

  let items = [];

  if(room === 'prologue') {
    items = [
      { done: S.pro.examined,       label: 'Annotate the intake document (Step 1)' },
      { done: S.pro.roleTaskDone,   label: 'Complete your role puzzle (Step 2)' },
      { done: S.pro.misalignDone,   label: 'Identify the misalignment (Step 3)' },
    ];
  } else if(room === 'room1') {
    items = [
      { done: S.r1.finalDone || S.r1.claimSubmitted, label: 'Submit your historical claim' },
      { done: S.r1.witnessUnlocked || S.r1.analystMapDone || S.r1.signalAuditDone || S.r1.provDone,
        label: 'Complete your role task and access testimony' },
    ];
    const ref1 = document.getElementById('ref-1')?.value?.trim() || '';
    const ref2 = document.getElementById('ref-2')?.value?.trim() || '';
    items.push({ done: ref1.length >= 15 && ref2.length >= 15, label: 'Respond to both reflection prompts' });
  } else if(room === 'room2') {
    const r1 = document.getElementById('r2-rank-1')?.value || '';
    const conf = document.querySelector('input[name="r2conf"]:checked');
    const sat  = document.getElementById('r2-saturation-resp')?.value?.trim() || '';
    items = [
      { done: !!r1,        label: 'Task A: Rank the sources' },
      { done: !!conf,      label: 'Task B: Rate your confidence after reading' },
      { done: sat.length >= 20, label: 'Task C: Name what abundance obscured' },
    ];
  } else if(room === 'room3') {
    const mc   = document.querySelector('input[name="r3mc"]:checked');
    const find = document.getElementById('r3-echo-finding')?.value?.trim() || '';
    items = [
      { done: echoTraced >= 3,     label: 'Examine at least 3 of 7 citation entries' },
      { done: !!mc,                label: 'Answer the corroboration MC question' },
      { done: find.length >= 25,   label: 'Write your echo analysis' },
    ];
  } else if(room === 'room4') {
    const mc  = document.querySelector('input[name="r4rank"]:checked');
    const br  = document.getElementById('r4-bury-reason')?.value?.trim() || '';
    const aud = document.getElementById('r4-platform-audit')?.value?.trim() || '';
    items = [
      { done: !!mc,             label: 'Task A: Identify what the ranking is doing' },
      { done: br.length >= 10,  label: 'Task B: Rank the buried sources + explain' },
      { done: aud.length >= 25, label: 'Task C: Write your platform audit' },
    ];
  } else if(room === 'room5') {
    const aud = document.getElementById('r5-synthesis-audit')?.value?.trim() || '';
    items = [
      { done: r5AuditsDone >= 3,   label: 'Open and audit at least 3 AI claims' },
      { done: aud.length >= 25,    label: 'Write your synthesis audit' },
    ];
  }

  const allDone = items.every(i => i.done);
  el.innerHTML = `
    <div class="progress-gate-title">${allDone ? '✓ Ready to advance' : 'Before you advance'}</div>
    ${items.map(i => `
      <div class="progress-item${i.done ? ' done' : ''}">
        <span class="pcheck">${i.done ? '✓' : '○'}</span>
        ${i.label}
      </div>`).join('')}
  `;
  el.style.borderColor = allDone
    ? 'rgba(74,138,114,0.45)'
    : 'rgba(201,152,42,0.2)';
}

// Call updateRoomProgress whenever a form field changes or a task completes
// Patch markTask to also update the room progress
const _origMarkTask = window.markTask;

function markTask(id){
  const el=document.getElementById(id);
  if(!el) return;
  el.classList.add('done');
  // Update progress for current room
  if(id.startsWith('pt')) updateRoomProgress('prologue');
  else if(id.startsWith('r1')) updateRoomProgress('room1');
  else if(id.startsWith('r2')) updateRoomProgress('room2');
  else if(id.startsWith('r3')) updateRoomProgress('room3');
  else if(id.startsWith('r4')) updateRoomProgress('room4');
  else if(id.startsWith('r5')) updateRoomProgress('room5');
}

function showModal(tag,title,body,prin){
  document.getElementById('modal-tag').textContent=tag;
  document.getElementById('modal-title').textContent=title;
  document.getElementById('modal-body').innerHTML=body;
  document.getElementById('modal-prin').textContent=prin;
  document.getElementById('modal-overlay').classList.add('visible');
}
function closeModal(){ document.getElementById('modal-overlay').classList.remove('visible'); }

let toastT;
function showToast(label,msg,ms=3000){
  const t=document.getElementById('toast');
  document.getElementById('toast-label').textContent=label;
  document.getElementById('toast-msg').textContent=msg;
  t.classList.add('visible');
  clearTimeout(toastT);
  toastT=setTimeout(()=>t.classList.remove('visible'),ms);
}

const HINTS_MAP={
  pro: ROLES,
  r1: ROLES
};

async function useHint(room){
  if(S.hints<=0){showToast('No Hints Remaining','You have used all available hints.');return;}
  S.hints--;
  const hcEl=document.getElementById('hc-'+room);
  if(hcEl) hcEl.textContent=S.hints+' remaining';
  setSignal(S.signal-1);
  const hint=ROLES[S.role]?.hints?.[room]||'Read carefully. Notice who produced each source and what perspective it represents.';
  showModal('Hint Used -- Signal Reduced','Auditor Guidance',hint,'Using a hint reduces your signal. The archive rewards patient reading.');
  await post({action:'updateSession',session_id:S.sessionId,hints_used:3-S.hints});
  await post({action:'saveSignal',session_id:S.sessionId,room,event:'hint_used',signal_before:S.signal+1,signal_after:S.signal,delta:-1});
}


