// Quest sync helper -- call whenever a quest step changes
async function syncQuestProgress(questId, stepsDone, isComplete) {
  const q = QUESTS[questId];
  if(!q || !S.sessionId) return;
  await post({
    action:'updateQuestProgress',
    session_id:S.sessionId, student_name:S.studentName,
    quest_id:questId, quest_name:q.name,
    steps:stepsDone,
    is_complete:isComplete||false,
    pts_awarded:isComplete?q.rewardPts:0
  });
  if(isComplete) {
    q.complete = true;
    gainPts(q.rewardPts, 'Quest complete: '+q.name+' (+'+q.rewardPts+')', 'quest');
    showToast('Quest Complete', q.name+' -- '+q.reward);
    renderBagQuests();
  }
}

