// Track which trajectory actions the student has accumulated
const S3 = {
  trajectoryActions: new Set(),   // set of action strings earned
  trajectoryHints: []             // visible path hints shown in HUD
};

// Call this whenever a qualifying action occurs
function earnTrajectoryAction(action) {
  S3.trajectoryActions.add(action);
  updateTrajectoryDisplay();
  // Persist to sheets
  if(S.sessionId) post({action:'updateSession', session_id:S.sessionId,
    current_rank:S2.rank, archive_pts:S2.pts});
}

// Compute which endings the student is moving toward
function computeTrajectories() {
  const results = [];
  for(const [id, ending] of Object.entries(ENDINGS)) {
    const earned = ending.trajectory_actions.filter(a => S3.trajectoryActions.has(a));
    if(earned.length > 0) {
      results.push({id, ending, earned, pct: earned.length / ending.min_required});
    }
  }
  return results.sort((a,b) => b.pct - a.pct);
}

// Show trajectory hints in the HUD side panel
function updateTrajectoryDisplay() {
  const el = document.getElementById('trajectory-display');
  if(!el) return;
  const paths = computeTrajectories();
  if(!paths.length) {
    el.innerHTML = '<div class="traj-empty">Paths form through choices, not points.</div>';
    return;
  }
  el.innerHTML = paths.slice(0,2).map(({id, ending, earned, pct}) => {
    const pctCapped = Math.min(1, pct);
    return `<div class="traj-item">
      <div class="traj-icon">${ending.icon}</div>
      <div class="traj-content">
        <div class="traj-label">${ending.label}</div>
        <div class="traj-bar"><div class="traj-fill" style="width:${Math.round(pctCapped*100)}%"></div></div>
        <div class="traj-hint">${ending.trajectory_desc}</div>
      </div>
    </div>`;
  }).join('');
}

// Whether this ending is unlockable given trajectory actions
function canUnlockEnding(id) {
  const ending = ENDINGS[id];
  if(!ending) return false;
  const earned = ending.trajectory_actions.filter(a => S3.trajectoryActions.has(a));
  return earned.length >= ending.min_required;
}

