// ── Dashboard sync helper -- call after any significant action ───
function syncDashboard(room_override) {
  if(!S.sessionId) return;
  post({action:'updateDashboard',
    session_id:S.sessionId, student_name:S.studentName, class_period:S.period,
    role:S.role, current_room:room_override||currentRoom(),
    archive_pts:S2.pts, current_rank:S2.rank||'novice', signal_score:S.signal,
    rooms_completed:S.roomsComplete||0,
    objects_found:Object.keys(S2.inventory||{}).length,
    quests_complete:0, passages_entered:0, loop_count:0,
    hints_used:3-S.hints, locker_count:(S.locker||[]).length, status:'active'});
}

// ── Debounced dashboard sync (max 1 call per 10s per room) ──────
let _dashSyncTimer = null;
function syncDashboardDebounced() {
  clearTimeout(_dashSyncTimer);
  _dashSyncTimer = setTimeout(() => syncDashboard(), 10000);
}

function gainPts(amount, label, type='action') {
  S2.pts += amount;
  S2.log.unshift({desc:label, pts:amount, time: new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'})});
  S2.ptsLog.push({amount, label, type});

  const el = document.getElementById('hud-pts');
  if(el) { el.textContent = S2.pts; el.style.transform='scale(1.22)'; setTimeout(()=>el.style.transform='scale(1)',280); }
  flyPts(amount);
  updateInk(amount);
  checkRank();
  renderBagLog();

  // sync to sheets (best effort)
  if(S.sessionId) {
    post({action:'logPoints', session_id:S.sessionId, student_name:S.studentName,
      class_period:S.period, event_type:type, event_label:label, pts_change:amount, running_total:S2.pts,
      room:currentRoom(), source_id:''});
  }
}

function currentRoom() {
  const screens = ['screen-landing','screen-config','screen-roles','screen-prologue','screen-room1','screen-r1-complete'];
  const active = document.querySelector('.screen.active');
  if(!active) return '';
  const map = {
    'screen-prologue':'prologue','screen-room1':'room1','screen-r1-complete':'room1_complete'
  };
  return map[active.id] || active.id;
}

function flyPts(amount) {
  const el = document.createElement('div');
  el.className = 'pts-fly' + (amount < 0 ? ' neg' : '');
  el.textContent = (amount > 0 ? '+' : '') + amount;
  el.style.cssText = `position:fixed;bottom:90px;right:90px;font-family:'IM Fell English SC',serif;font-size:15px;color:${amount<0?'var(--el)':'var(--go)'};pointer-events:none;z-index:2000;animation:fadeUp 1.2s ease both;`;
  document.body.appendChild(el);
  setTimeout(() => el.remove(), 1300);
}

function updateInk(amount) {
  if(amount > 0) S2.ink = Math.min(10, S2.ink + Math.ceil(amount/25));
  else S2.ink = Math.max(0, S2.ink - 1);
  const dots = document.querySelectorAll('#ink-dots .ink-dot');
  dots.forEach((d,i) => { d.classList.toggle('lit', i < S2.ink); });
}

function checkRank() {
  const newRank = RANKS.reduce((cur, r) => S2.pts >= r.min ? r : cur, RANKS[0]);
  if(newRank.id !== S2.rank) {
    const old = S2.rank;
    S2.rank = newRank.id;
    updateRankBadge(newRank);
    showRankReveal(newRank);
    if(S.sessionId) post({action:'recordRankChange',session_id:S.sessionId,student_name:S.studentName,class_period:S.period,rank_from:old,rank_to:newRank.id,pts_at_change:S2.pts,room:currentRoom()});
  } else {
    updateRankBadge(newRank);
  }
}

function updateRankBadge(rank) {
  const el = document.getElementById('hud-rank');
  if(el) { el.className='rank-badge '+rank.id; el.textContent=rank.label; }
}

