function checkHistoryBonus(text, room) {
  if(!text || text.length < 8) return;
  const lower = text.toLowerCase();

  Object.entries(HISTORY_TRIGGERS).forEach(([termId, trigger]) => {
    if(_vocabAwarded.has('hist_'+termId)) return;
    if(trigger.room_filter && !trigger.room_filter.includes(room)) return;

    const matched = trigger.words.some(w => lower.includes(w));
    if(!matched) return;

    const objId = trigger.object;
    if(S2.inventory[objId]) return;

    _vocabAwarded.add('hist_'+termId);

    setTimeout(() => {
      // Merge history object into OBJECTS at runtime so discoverObject works
      if(!OBJECTS[objId] && HISTORY_OBJECTS[objId]) {
        OBJECTS[objId] = HISTORY_OBJECTS[objId];
      }
      discoverObject(objId, true);
      _showHistoryDiscovery(objId, trigger.context, trigger.pts);
      post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
        class_period:S.period, room:room,
        task_id:'HIST_'+termId.toUpperCase(),
        task_label:'Historical context: '+termId,
        response_type:'history_trigger',
        response_value:text.substring(0, 200),
        is_correct:true, signal_delta:0.5,
        standards_addressed:'APUSH KC-7.3,HS-2',
        skill_category:'Historical Contextualization'});
    }, 1400);
  });
}

function _showHistoryDiscovery(objId, context, pts) {
  const obj = OBJECTS[objId] || HISTORY_OBJECTS[objId];
  if(!obj) return;
  const toast = document.getElementById('disc-toast');
  if(toast) {
    document.getElementById('dt-icon').innerHTML = '&#128209;';
    document.getElementById('dt-label').textContent = 'Historical Context: Outside Knowledge';
    document.getElementById('dt-name').textContent = obj.name;
    document.getElementById('dt-desc').textContent = context;
    document.getElementById('dt-effect').textContent = 'Archive effect: '+obj.effect;
    toast.classList.add('visible');
    setTimeout(() => toast.classList.remove('visible'), 7000);
  }
}

function checkVocabBonus(text, room) {
  if(!text || text.length < 8) return;
  const lower = text.toLowerCase();

  Object.entries(VOCAB_TRIGGERS).forEach(([termId, trigger]) => {
    // Only award once per session per term
    if(_vocabAwarded.has(termId)) return;

    const matched = trigger.words.some(w => lower.includes(w));
    if(!matched) return;

    // Don't award if object already in bag
    if(S2.inventory[trigger.object]) return;

    // Award it
    _vocabAwarded.add(termId);

    // Small delay so it appears after main save toast
    setTimeout(() => {
      discoverObject(trigger.object, true); // skipToast = true, we show our own
      _showVocabDiscovery(trigger.object, trigger.context);
      post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
        class_period:S.period, room:room,
        task_id:'VOCAB_'+termId.toUpperCase(),
        task_label:'Vocabulary recognition: '+termId,
        response_type:'vocab_trigger',
        response_value:text.substring(0, 200),
        is_correct:true, signal_delta:0,
        standards_addressed:'HS-1,AS-2',
        skill_category:'Analytical Vocabulary'});
    }, 900);
  });
}

function _showVocabDiscovery(objId, context) {
  const obj = OBJECTS[objId];
  if(!obj) return;

  // Use a distinctive toast style for vocab discoveries
  const toast = document.getElementById('disc-toast');
  if(toast) {
    document.getElementById('dt-icon').innerHTML = '&#128220;';
    document.getElementById('dt-label').textContent = 'Lexicon Entry Discovered';
    document.getElementById('dt-name').textContent = obj.name;
    document.getElementById('dt-desc').textContent = context;
    document.getElementById('dt-effect').textContent = 'Bag effect: '+obj.effect;
    toast.classList.add('visible');
    setTimeout(() => toast.classList.remove('visible'), 6000);
  }
}

function discoverObject(objId, skipToast) {
  if(S2.inventory[objId]) return;
  const obj = OBJECTS[objId];
  if(!obj) return;
  S2.inventory[objId] = {found:true, used:false, foundAt: new Date().toISOString()};
  S2.newItems.push(objId);
  gainPts(obj.pts, 'Found: '+obj.name, 'object_find');
  if(!skipToast) showDiscovery(obj);
  updateBagCount();
  renderBagObjects();
  if(S2.journeyEffects.indexOf(obj.journeyEffect) === -1) S2.journeyEffects.push(obj.journeyEffect);
  if(S.sessionId) post({action:'recordObjectFind',session_id:S.sessionId,student_name:S.studentName,object_id:objId,object_name:obj.name,object_type:obj.cat,room_found:currentRoom(),how_found:obj.howToFind,pts_awarded:obj.pts,ink_type:obj.ink});
}

function discoverFromRail(objId) {
  const obj = OBJECTS[objId];
  if(!obj) return;
  if(S2.inventory[objId]) { showToast('Already Found', obj.name+' is already in your bag.'); return; }
  discoverObject(objId);
}

function showDiscovery(obj) {
  document.getElementById('dt-icon').innerHTML = obj.icon;
  document.getElementById('dt-label').textContent = {A:'Tool Found',B:'Item Found',C:'Clue Found',D:'Key Found'}[obj.cat]||'Discovery';
  document.getElementById('dt-name').textContent = obj.name;
  document.getElementById('dt-desc').textContent = obj.desc;
  document.getElementById('dt-effect').textContent = 'Effect: '+obj.effect;
  const t = document.getElementById('disc-toast');
  if(t) { t.classList.add('visible'); setTimeout(()=>t.classList.remove('visible'), 4800); }
}

function updateBagCount() {
  const count = Object.keys(S2.inventory).length;
  const el = document.getElementById('bag-count');
  if(el) { el.textContent=count; el.style.display=count>0?'flex':'none'; }
}

// ================================================================
// V4 BAG PANEL
// ================================================================
function toggleBag() {
  const p = document.getElementById('bag-panel');
  p.classList.toggle('open');
  if(p.classList.contains('open')) { S2.newItems=[]; renderBagObjects(); renderBagQuests(); renderBagPrinciples(); renderBagLog(); }
}

function bagTab(id, btn) {
  document.querySelectorAll('.bag-tab').forEach(t=>t.classList.remove('active'));
  btn.classList.add('active');
  ['objects','quests','cards','log'].forEach(tid => {
    const el = document.getElementById('bag-'+tid);
    if(el) el.style.display = tid===id ? 'block' : 'none';
  });
}

function renderBagObjects() {
  const el = document.getElementById('bag-objects');
  if(!el) return;
  const found = Object.keys(S2.inventory);
  if(!found.length) { el.innerHTML='<div style="font-family:Crimson Pro,serif;font-style:italic;font-size:0.78rem;color:var(--sm);padding:0.5rem;">Nothing in your bag yet. Explore carefully.</div>'; return; }
  el.innerHTML = found.map(k => {
    const obj = OBJECTS[k];
    if(!obj) return '';
    return `<div class="obj-item${S2.newItems.includes(k)?' new':''}">
      <div class="obj-icon">${obj.icon}</div>
      <div class="obj-info">
        <div class="obj-name">${obj.name}</div>
        <div class="obj-desc">${obj.desc}</div>
        <div class="obj-pts">${obj.pts>0?'+'+obj.pts+' pts earned':'Active object'}</div>
      </div>
    </div>`;
  }).join('');
}

function renderBagQuests() {
  const el = document.getElementById('bag-quests');
  if(!el) return;
  el.innerHTML = Object.entries(QUESTS).map(([id,q]) => {
    const cls = q.complete?'done':q.active?'active':'';
    return `<div class="quest-item ${cls}">
      <div class="quest-name">${q.name}${q.complete?' -- Complete':q.active?'':' -- Locked'}</div>
      <div style="font-family:Crimson Pro,serif;font-style:italic;font-size:0.7rem;color:var(--sm);margin-bottom:4px;">${q.desc}</div>
      ${q.steps.map(s=>`<div class="quest-step${s.done?' done':''}"><div class="qsdot"></div><span>${s.desc}</span></div>`).join('')}
      <div style="font-family:JetBrains Mono,monospace;font-size:7px;color:var(--go);letter-spacing:0.07em;margin-top:4px;">${q.reward}</div>
    </div>`;
  }).join('');
}

function renderBagPrinciples() {
  const el = document.getElementById('bag-cards');
  if(!el) return;
  if(!S.principles || !S.principles.length) { el.innerHTML='<div style="font-family:Crimson Pro,serif;font-style:italic;font-size:0.78rem;color:var(--sm);">Earned after each room.</div>'; return; }
  el.innerHTML = S.principles.map(p=>`<div style="background:rgba(201,152,42,0.05);border:0.5px solid rgba(201,152,42,0.2);border-left:2px solid var(--go);padding:0.6rem;margin-bottom:5px;font-family:Crimson Pro,serif;font-style:italic;font-size:0.78rem;color:var(--pa);">${p}</div>`).join('');
}

