async function submitRoom5() {
  const audit = document.getElementById('r5-synthesis-audit')?.value?.trim();
  if(r5AuditsDone < 3) {
    showToast('Open more claims','Open and examine at least 3 of the 6 AI claims before submitting your synthesis audit.');
    return;
  }
  if(!audit || audit.length < 25) { showToast('Synthesis required','Write your synthesis audit before the Final Protocol -- name what the AI summary submerged.'); return; }
  checkVocabBonus(audit, 'room5');
  checkHistoryBonus(audit, 'room5');
  const notesSmoothing = audit.toLowerCase().includes('smooth') || audit.toLowerCase().includes('disappear') ||
    audit.toLowerCase().includes('hidden') || audit.toLowerCase().includes('absent') ||
    audit.toLowerCase().includes('omit') || audit.toLowerCase().includes('conceal');
  if(notesSmoothing) { gainPts(40, 'Smoothness identified as selection: synthesis is not neutral (+40)', 'synthesis'); }
  await post({action:'saveResponse', session_id:S.sessionId, student_name:S.studentName,
    room:'room5', task_id:'R5_SYNTHESIS', task_label:'AI synthesis audit',
    response_type:'long_text', response_value:audit, is_correct:notesSmoothing, signal_delta:1,
    standards_addressed:'AS-5,AS-6,HS-8', skill_category:'Synthesis Interrogation'});
  document.getElementById('lb-r5-h').classList.add('open'); document.getElementById('lb-r5-h').textContent='ok';
  await post({action:'updateSession', session_id:S.sessionId, current_room:'final', rooms_completed:5});
  syncDashboard('final');
  // Trigger handoff decision before final
  const handoff = await showHandoffDecision();
  if(handoff) { document.getElementById('lb-r5-a').classList.add('open'); document.getElementById('lb-r5-a').textContent='ok'; }
  await showSmoothnessCheck('room5');
  await showEndingChooser();
  showToast('Room 5 Complete', 'Proceeding to Final Escape Protocol.');
  setTimeout(() => enterFinal(), 1800);
}

// ── Final Protocol submission ──────────────────────────────────────
// ── Escape Protocol autosave ─────────────────────────────────────
const EP_SAVE_KEY = 'escape_archive_ep_draft';
let _epAutosaveTimer = null;

function initEscapeProtocol() {
  // Restore saved drafts
  try {
    const saved = JSON.parse(localStorage.getItem(EP_SAVE_KEY) || 'null');
    if(saved && S.studentName && saved.student === S.studentName) {
      [1,2,3,4,5,6,7].forEach(i => {
        const el = document.getElementById('final-q'+i);
        if(el && saved['q'+i]) el.value = saved['q'+i];
      });
      const status = document.getElementById('ep-autosave-status');
      if(status) { status.textContent = 'Draft restored from ' + new Date(saved.ts).toLocaleTimeString(); status.classList.add('saved'); }
    }
  } catch(e) {}
  // Attach autosave listeners
  [1,2,3,4,5,6,7].forEach(i => {
    const el = document.getElementById('final-q'+i);
    if(!el) return;
    // Char counter
    const ctr = document.getElementById('ep-cc-'+i);
    el.oninput = ()=>{
      if(ctr) { ctr.textContent = el.value.length + ' characters'; ctr.classList.toggle('warn', el.value.length > 0 && el.value.length < 30); }
      clearTimeout(_epAutosaveTimer);
      _epAutosaveTimer = setTimeout(epAutosave, 800);
    };
  });
}

function epAutosave() {
  try {
    const data = { student: S.studentName, ts: Date.now() };
    [1,2,3,4,5,6,7].forEach(i => {
      const el = document.getElementById('final-q'+i);
      data['q'+i] = el?.value||'';
    });
    localStorage.setItem(EP_SAVE_KEY, JSON.stringify(data));
    const status = document.getElementById('ep-autosave-status');
    if(status) {
      status.textContent = 'Draft autosaved at ' + new Date().toLocaleTimeString();
      status.classList.add('saved');
      setTimeout(()=>{ status.classList.remove('saved'); }, 3000);
    }
  } catch(e) {}
}

async function submitFinalProtocol() {
  const vals = [1,2,3,4,5,6,7].map(i => document.getElementById('final-q'+i)?.value?.trim()||'');
  const empty = vals.filter(v => v.length < 10);
  if(empty.length > 3) {
    showToast('Incomplete protocol','Complete at least four of the seven components before submitting.'); return;
  }
  // Limitation claim is required -- component 3
  if(!vals[2] || vals[2].length < 10) {
    showToast('Limitation claim required','Component 3 is required: name what cannot responsibly be said given this archive. This is not optional.');
    // Highlight the field
    const q3 = document.getElementById('final-q3');
    if(q3) { q3.style.borderColor = 'rgba(192,72,40,0.7)'; q3.focus(); }
    return;
  }
  const _roleReflection = vals[6] || '';
  await post({action:'saveFinal',
    session_id:S.sessionId, student_name:S.studentName, team_name:'', role:S.role,
    historical_claim:vals[0], curation_claim:vals[1], limitation_claim:vals[2],
    escape_protocol_q1:vals[0], escape_protocol_q2:vals[1], escape_protocol_q3:vals[2],
    escape_protocol_q4:vals[3], escape_protocol_q5:vals[4], escape_protocol_q6:vals[5],
    signal_final:S.signal, rooms_completed:S.roomsComplete, locker_count:S.locker.length,
    hints_used:3-S.hints, caption_rewrite:_roleReflection, caption_rewrite_room1:vals[0]});
  if(_roleReflection.length > 10) {
    await recordRoleShift(S.role+'_entry', 'answerable_curator', _roleReflection);
  }
  gainPts(50, 'Final Escape Protocol submitted (+50)', 'synthesis');
  await post({action:'updateSession', session_id:S.sessionId, status:'complete', rooms_completed:5,
    archive_pts:S2.pts, ending_path:_endingChoice||''});
  syncDashboard('final');
  showModal('Escape Protocol Submitted', 'The archive does not have one exit.',
    'You have submitted your Escape Protocol. Your work -- claims, limitations, refusals, unarchivables, trajectory -- has been recorded. The exhibit can now publish, or not, depending on what you decided.<br><br>You do not escape the archive. You learn to enter it differently.',
    'Return to the room that changed what you were asking.'
  );
}

