function stdsHTML(codes) {
  return codes.map(c => {
    if(c.startsWith('AS-')) return `<span class="task-std arch">${AS[c]?.short||c}</span>`;
    return `<span class="task-std apush">${c}</span>`;
  }).join('');
}

// ================================================================
// V4 EXPANDED TASK BUILDER (called after buildRoom1)
// ================================================================
function buildExpandedTasks() {
  const R = ROLES[S.role];
  if(!R || !R.r1Tasks) return;
  const tp = document.getElementById('r1-tasks');
  if(!tp) return;
  tp.innerHTML = '';
  R.r1Tasks.forEach((t, i) => {
    const isOpt = t.id && t.id.includes('opt');
    const numLabel = isOpt ? 'DEEPER PRACTICE' : 'TASK 00'+(i+1);
    const stdBadges = t.stds ? stdsHTML(t.stds) : '';
    tp.insertAdjacentHTML('beforeend', `<div class="task${isOpt?' optional-task':''}" id="${t.id}">
      <div class="task-num">${numLabel}</div>
      <div class="task-desc">${t.desc}</div>
      ${stdBadges ? `<div class="task-stds">${stdBadges}</div>` : ''}
    </div>`);
  });
}

