const _origApplyRoleUI = applyRoleUI;
applyRoleUI = function() {
  _origApplyRoleUI();
  // set hud role badge
  const R = ROLES[S.role];
  const hb = document.getElementById('hud-role-badge');
  if(hb) { hb.className='hud-role-badge '+R.color; hb.textContent=R.label; }
};

// Hook into goTo to trigger HUD room update
const _origGoTo = goTo;
goTo = function(id) {
  // Navigation always runs first, unconditionally
  _origGoTo(id);
  // Everything below is best-effort -- errors must not block navigation
  try {
    const roomMap = {
      'screen-prologue':'prologue','screen-room1':'room1','screen-r1-complete':'room1',
      'screen-room2':'room2','screen-room3':'room3','screen-room4':'room4',
      'screen-room5':'room5','screen-final':'final'
    };
    if(roomMap[id]) showHUD(roomMap[id]);
  } catch(e) {}

  // Trajectory and dashboard logic only fires after startGame() has run
  if(!S || !S.sessionId) return;

  try { updateTrajectoryDisplay(); } catch(e) {}

  // Initialize escape protocol autosave when final screen is shown
  if(id === 'screen-final') { try { initEscapeProtocol(); } catch(e) {} }

  try {
    ['r2','r3','r4','r5'].forEach(rm => {
      const el = document.getElementById('trajectory-display-'+rm);
      if(!el) return;
      const paths = computeTrajectories();
      if(!paths.length) {
        el.innerHTML='<div style="font-family:Crimson Pro,serif;font-style:italic;font-size:0.68rem;color:var(--sm);">Paths form through choices.</div>';
        return;
      }
      el.innerHTML = paths.slice(0,2).map(({id:eid, ending, earned, pct}) => {
        const pctCapped = Math.min(1, pct);
        return `<div class="traj-item"><div class="traj-icon">${ending.icon}</div><div class="traj-content"><div class="traj-label">${ending.label}</div><div class="traj-bar"><div class="traj-fill" style="width:${Math.round(pctCapped*100)}%"></div></div><div class="traj-hint">${ending.trajectory_desc}</div></div></div>`;
      }).join('');
    });
  } catch(e) {}

  try {
    if(id==='screen-r1-complete') {
      syncDashboard();
      const el = document.getElementById('r1c-traj-content');
      if(el) {
        const paths = computeTrajectories();
        if(!paths.length) {
          el.innerHTML = '<span style="color:var(--sm);">No trajectory paths earned yet. Paths form through choices in Rooms 2 through 5. The archive is not finished with you.</span>';
        } else {
          el.innerHTML = paths.map(({ending, earned, pct}) => {
            const pctDisplay = Math.round(Math.min(1, pct) * 100);
            return `<div style="margin-bottom:0.55rem;">
              <div style="display:flex;align-items:center;gap:0.5rem;margin-bottom:3px;">
                <span style="font-size:1rem;">${ending.icon}</span>
                <span style="font-family:'IM Fell English SC',serif;font-size:0.82rem;color:var(--iv);">${ending.label}</span>
                <span style="font-family:'JetBrains Mono',monospace;font-size:6.5px;color:var(--go);margin-left:auto;">${pctDisplay}% of qualifying actions</span>
              </div>
              <div style="height:3px;background:rgba(201,152,42,0.1);border-radius:2px;"><div style="height:100%;width:${pctDisplay}%;background:linear-gradient(90deg,var(--gi),var(--go));border-radius:2px;"></div></div>
              <div style="font-family:'Crimson Pro',serif;font-size:0.7rem;color:var(--sm);font-style:italic;margin-top:3px;">${ending.trajectory_desc}</div>
            </div>`;
          }).join('');
        }
      }
    }
  } catch(e) {}
};

// Hook into gainPts calls from original saveArt for signal points
