setSignal = function(n) {
  _origSetSignal(n);
  updateInk(n > S.signal ? 3 : -3);
};

// ================================================================
// V3 MARK UNARCHIVABLE UI
// ================================================================
async function showMarkUnarchivable() {
  const types = [
    {val:'accidental_loss',        label:'Accidental loss -- destroyed, misplaced, or never filed'},
    {val:'structural_exclusion',   label:'Structural exclusion -- the archive was not built to hold it'},
    {val:'deliberate_suppression', label:'Deliberate suppression -- removed or withheld intentionally'},
    {val:'community_protection',   label:'Community protection -- should not be publicly circulated; belongs to its source community'},
    {val:'simply_gone',            label:'Simply gone -- no trace remains; the absence itself is the only evidence'}
  ];
  const type = await new Promise(resolve => {
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(10,12,8,0.88);z-index:1400;display:flex;align-items:center;justify-content:center;';
    overlay.innerHTML = `<div style="background:var(--gv);border:0.5px solid rgba(139,58,42,0.4);padding:1.8rem;max-width:510px;width:90%;">
      <div style="font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.18em;color:var(--er);text-transform:uppercase;margin-bottom:0.65rem;">What Cannot Be Reconstructed</div>
      <div style="font-family:'IM Fell English SC',serif;font-size:1rem;color:var(--iv);margin-bottom:0.45rem;">Name what the archive cannot account for.</div>
      <div style="font-family:'Crimson Pro',serif;font-size:0.82rem;color:var(--pd);font-style:italic;margin-bottom:0.85rem;">Marking the remnant is not an admission of failure. It is part of responsible historical argument. A claim that does not name what it cannot recover is not more complete -- it is less honest. This entry will appear in your final output alongside your claim.</div>
      <textarea class="arch-textarea" id="rem-text" style="min-height:58px;margin-bottom:0.65rem;" placeholder="What cannot be reconstructed, and why does it matter for the claim you are building?"></textarea>
      <div style="font-family:'JetBrains Mono',monospace;font-size:7px;color:var(--gi);text-transform:uppercase;letter-spacing:0.12em;margin-bottom:0.35rem;">What kind of absence is this?</div>
      <div style="display:flex;flex-direction:column;gap:0.35rem;margin-bottom:0.7rem;">
        ${types.map(t=>`<button class="btn-task" onclick="this.dataset.val='${t.val}';document.querySelectorAll('[id^=rem-type-btn-]').forEach(b=>b.style.borderColor='');this.style.borderColor='rgba(201,152,42,0.5)';" id="rem-type-btn-${t.val}">${t.label}</button>`).join('')}
      </div>
      <div style="display:flex;gap:0.5rem;">
        <button class="btn-gold" style="font-size:0.75rem;padding:0.45rem 1rem;" onclick="
          const txt=document.getElementById('rem-text').value.trim();
          const type=Array.from(document.querySelectorAll('[id^=rem-type-btn-]')).find(b=>b.style.borderColor.includes('42'))?.id.replace('rem-type-btn-','');
          if(!txt){alert('Describe what cannot be reconstructed before marking it.');return;}
          this.closest('div').parentElement.parentElement.__resolve({text:txt,type:type||'unknown'});
          this.closest('div').parentElement.parentElement.remove();">Record this in the remnant panel</button>
        <button class="btn-ghost" style="font-size:0.75rem;" onclick="this.closest('div').parentElement.parentElement.__resolve(null);this.closest('div').parentElement.parentElement.remove();">Cancel</button>
      </div>
    </div>`;
    overlay.__resolve = resolve;
    document.body.appendChild(overlay);
  });
  if(type) await markUnarchivable(type.text, type.type);
}

// Protocol decision UI (shown when student opens certain sensitive artifacts)
async function showProtocolDecision(artifactId, artifactName) {
  return new Promise(resolve => {
    const overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(10,12,8,0.9);z-index:1400;display:flex;align-items:center;justify-content:center;';
    overlay.innerHTML = `<div style="background:var(--gv);border:0.5px solid rgba(74,138,114,0.35);padding:1.8rem;max-width:510px;width:90%;">
      <div style="font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.18em;color:var(--vd);text-transform:uppercase;margin-bottom:0.65rem;">Access Decision -- Part of the Historical Method</div>
      <div style="font-family:'IM Fell English SC',serif;font-size:1rem;color:var(--iv);margin-bottom:0.55rem;">${artifactName}</div>
      <div style="font-family:'Crimson Pro',serif;font-size:0.83rem;color:var(--pd);font-style:italic;margin-bottom:0.85rem;">This material may involve community records, sensitive testimony, or restricted sources. Deciding how to access historical material is itself a historical act. This is not a bureaucratic step. It is an ethical judgment that will appear in your final record.</div>
      <div style="display:flex;flex-direction:column;gap:0.4rem;margin-bottom:0.7rem;">
        <button class="btn-task" onclick="resolveProtocol('open_full','Open fully -- I take responsibility for how I use this',this)">Open fully -- I take responsibility for how I use this</button>
        <button class="btn-task" onclick="resolveProtocol('open_restricted','Open for this audit only -- not for public circulation',this)">Open for this audit only -- not for public circulation without further consideration</button>
        <button class="btn-task" onclick="resolveProtocol('request_permission','Access with named purpose -- I will explain why',this)">Access with a named purpose -- I will explain the terms under which I am reading this</button>
        <button class="btn-task" onclick="resolveProtocol('defer','Decline to open -- this material is not mine to exhibit',this)">Decline to open -- this material is not mine to exhibit, or I need more context before deciding</button>
      </div>
      <div id="prot-reason-block" style="display:none;margin-top:0.5rem;">
        <div style="font-family:'Crimson Pro',serif;font-size:0.78rem;color:var(--pd);font-style:italic;margin-bottom:0.4rem;">Explain your decision. This reasoning will appear in your final record and the teacher view.</div>
        <textarea class="arch-textarea" id="prot-reason" style="min-height:55px;" placeholder="Your reasoning for this access decision..."></textarea>
        <button class="btn-gold" style="font-size:0.75rem;padding:0.45rem 1rem;margin-top:0.45rem;" onclick="confirmProtocol()">Record this decision</button>
      </div>
    </div>`;
    let _protChoice = null;
    overlay.__resolve = resolve;
    overlay.id = 'protocol-overlay';
    window.resolveProtocol = (choice, label, btn) => {
      _protChoice = {choice, label};
      document.querySelectorAll('#protocol-overlay .btn-task').forEach(b=>b.style.borderColor='');
      btn.style.borderColor = 'rgba(74,138,114,0.6)';
      document.getElementById('prot-reason-block').style.display = 'block';
    };
    window.confirmProtocol = async () => {
      const reason = document.getElementById('prot-reason').value.trim();
      overlay.remove();
      if(_protChoice) {
        await recordProtocol(artifactId, artifactName, _protChoice.choice, _protChoice.label, reason);
        overlay.__resolve({choice:_protChoice.choice, reason});
      }
    };
    document.body.appendChild(overlay);
  });
}

