// ================================================================
// Record each unique artifact interaction as a source encounter
let _sourcesEncountered = new Set();
async function trackSourceEncounter(sourceId) {
  if(_sourcesEncountered.has(sourceId)) return;
  _sourcesEncountered.add(sourceId);
  S2.saturationCount = _sourcesEncountered.size;
  recordSaturationCheck(currentRoom());
}

// Patch saveArt to track source encounters
const _origSaveArt = saveArt;
saveArt = async function(id, name, room, type, provenance) {
  trackSourceEncounter(id);
  return await _origSaveArt(id, name, room, type, provenance);
};

